using System;
using System.Collections.Generic;
using UnityEngine;

namespace Sttop5.Shared.Core
{
    /// <summary>
    /// 模块管理器，负责注册、激活、停用游戏模块。
    /// 管理从家园进入小游戏的完整生命周期。
    /// </summary>
    public class ModuleManager : Singleton<ModuleManager>
    {
        private readonly Dictionary<string, GameModule> _modules = new Dictionary<string, GameModule>();
        private GameModule _activeModule;

        /// <summary>当前激活的模块</summary>
        public GameModule ActiveModule => _activeModule;

        /// <summary>当前激活的模块ID，无模块时为 "home"</summary>
        public string ActiveModuleId => _activeModule != null ? _activeModule.ModuleId : "home";

        /// <summary>模块切换开始回调</summary>
        public event Action<string, string> OnModuleSwitching;

        /// <summary>模块切换完成回调</summary>
        public event Action<string> OnModuleSwitched;

        /// <summary>
        /// 注册一个游戏模块。
        /// </summary>
        public void RegisterModule(GameModule module)
        {
            if (module == null || string.IsNullOrEmpty(module.ModuleId))
            {
                Debug.LogError("[ModuleManager] 无法注册空模块或无ID的模块");
                return;
            }

            if (_modules.ContainsKey(module.ModuleId))
            {
                Debug.LogWarning($"[ModuleManager] 模块已注册，将被替换: {module.ModuleId}");
            }

            _modules[module.ModuleId] = module;
            Debug.Log($"[ModuleManager] 模块已注册: {module.DisplayName} ({module.ModuleId})");
        }

        /// <summary>
        /// 注销一个游戏模块。
        /// </summary>
        public void UnregisterModule(string moduleId)
        {
            if (_modules.ContainsKey(moduleId))
            {
                if (_activeModule != null && _activeModule.ModuleId == moduleId)
                {
                    DeactivateCurrentModule();
                }
                _modules.Remove(moduleId);
                Debug.Log($"[ModuleManager] 模块已注销: {moduleId}");
            }
        }

        /// <summary>
        /// 激活指定模块，通过场景加载。
        /// </summary>
        public void ActivateModule(string moduleId)
        {
            if (!_modules.TryGetValue(moduleId, out GameModule module))
            {
                Debug.LogError($"[ModuleManager] 未找到模块: {moduleId}");
                return;
            }

            if (_activeModule != null && _activeModule.ModuleId == moduleId)
            {
                Debug.LogWarning($"[ModuleManager] 模块已激活: {moduleId}");
                return;
            }

            string fromModule = ActiveModuleId;
            OnModuleSwitching?.Invoke(fromModule, moduleId);

            // 停用当前模块
            if (_activeModule != null)
            {
                _activeModule.Deactivate();
            }

            // 加载模块场景
            if (!string.IsNullOrEmpty(module.SceneName))
            {
                SceneLoader.Instance.LoadSceneAdditive(module.SceneName, () =>
                {
                    module.Activate();
                    _activeModule = module;
                    OnModuleSwitched?.Invoke(moduleId);

                    GlobalEventBus.Publish(new ModuleSwitchEvent
                    {
                        FromModule = fromModule,
                        ToModule = moduleId
                    });
                });
            }
            else
            {
                module.Activate();
                _activeModule = module;
                OnModuleSwitched?.Invoke(moduleId);
            }
        }

        /// <summary>
        /// 停用当前模块并返回家园。
        /// </summary>
        public void DeactivateCurrentModule()
        {
            if (_activeModule == null)
            {
                Debug.LogWarning("[ModuleManager] 当前无激活模块");
                return;
            }

            string moduleId = _activeModule.ModuleId;
            string sceneName = _activeModule.SceneName;

            _activeModule.Deactivate();

            if (!string.IsNullOrEmpty(sceneName))
            {
                SceneLoader.Instance.UnloadScene(sceneName);
            }

            _activeModule = null;
            Debug.Log($"[ModuleManager] 模块已停用，返回家园: {moduleId}");
        }

        /// <summary>
        /// 获取已注册的模块。
        /// </summary>
        public GameModule GetModule(string moduleId)
        {
            _modules.TryGetValue(moduleId, out GameModule module);
            return module;
        }

        /// <summary>
        /// 获取所有已注册模块。
        /// </summary>
        public IReadOnlyDictionary<string, GameModule> GetAllModules()
        {
            return _modules;
        }

        /// <summary>
        /// 保存所有模块的存档数据。
        /// </summary>
        public Dictionary<string, string> CollectAllModuleSaveData()
        {
            var result = new Dictionary<string, string>();
            foreach (var kvp in _modules)
            {
                try
                {
                    string data = kvp.Value.GetModuleSaveData();
                    if (!string.IsNullOrEmpty(data))
                    {
                        result[kvp.Key] = data;
                    }
                }
                catch (Exception e)
                {
                    Debug.LogError($"[ModuleManager] 获取模块存档失败: {kvp.Key} - {e.Message}");
                }
            }
            return result;
        }
    }
}

using System;
using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace Sttop5.Shared.Core
{
    /// <summary>
    /// 场景加载管理器，处理 Additive 场景加载/卸载。
    /// 所有场景切换通过此类进行，支持加载进度回调。
    /// </summary>
    public class SceneLoader : Singleton<SceneLoader>
    {
        private readonly HashSet<string> _loadedScenes = new HashSet<string>();
        private bool _isLoading = false;

        public bool IsLoading => _isLoading;
        public IReadOnlyCollection<string> LoadedScenes => _loadedScenes;

        /// <summary>
        /// 以 Additive 模式加载场景。
        /// </summary>
        public void LoadSceneAdditive(string sceneName, Action onLoaded = null)
        {
            if (_isLoading)
            {
                Debug.LogWarning($"[SceneLoader] 正在加载中，忽略请求: {sceneName}");
                return;
            }

            if (_loadedScenes.Contains(sceneName))
            {
                Debug.LogWarning($"[SceneLoader] 场景已加载: {sceneName}");
                onLoaded?.Invoke();
                return;
            }

            StartCoroutine(LoadSceneAdditiveCoroutine(sceneName, onLoaded));
        }

        /// <summary>
        /// 卸载已加载的 Additive 场景。
        /// </summary>
        public void UnloadScene(string sceneName, Action onUnloaded = null)
        {
            if (!_loadedScenes.Contains(sceneName))
            {
                Debug.LogWarning($"[SceneLoader] 场景未加载，无法卸载: {sceneName}");
                onUnloaded?.Invoke();
                return;
            }

            StartCoroutine(UnloadSceneCoroutine(sceneName, onUnloaded));
        }

        /// <summary>
        /// 卸载所有通过 SceneLoader 加载的场景（保留根场景）。
        /// </summary>
        public void UnloadAllScenes(Action onAllUnloaded = null)
        {
            if (_loadedScenes.Count == 0)
            {
                onAllUnloaded?.Invoke();
                return;
            }

            StartCoroutine(UnloadAllScenesCoroutine(onAllUnloaded));
        }

        /// <summary>
        /// 检查指定场景是否已加载。
        /// </summary>
        public bool IsSceneLoaded(string sceneName)
        {
            return _loadedScenes.Contains(sceneName);
        }

        private IEnumerator LoadSceneAdditiveCoroutine(string sceneName, Action onLoaded)
        {
            _isLoading = true;

            var op = SceneManager.LoadSceneAsync(sceneName, LoadSceneMode.Additive);
            if (op == null)
            {
                Debug.LogError($"[SceneLoader] 无法加载场景: {sceneName}");
                _isLoading = false;
                yield break;
            }

            while (!op.isDone)
            {
                yield return null;
            }

            _loadedScenes.Add(sceneName);

            Scene loadedScene = SceneManager.GetSceneByName(sceneName);
            if (loadedScene.IsValid())
            {
                SceneManager.SetActiveScene(loadedScene);
            }

            _isLoading = false;
            Debug.Log($"[SceneLoader] 场景已加载: {sceneName}");
            onLoaded?.Invoke();
        }

        private IEnumerator UnloadSceneCoroutine(string sceneName, Action onUnloaded)
        {
            _isLoading = true;

            var op = SceneManager.UnloadSceneAsync(sceneName);
            if (op == null)
            {
                Debug.LogError($"[SceneLoader] 无法卸载场景: {sceneName}");
                _isLoading = false;
                yield break;
            }

            while (!op.isDone)
            {
                yield return null;
            }

            _loadedScenes.Remove(sceneName);
            _isLoading = false;
            Debug.Log($"[SceneLoader] 场景已卸载: {sceneName}");
            onUnloaded?.Invoke();
        }

        private IEnumerator UnloadAllScenesCoroutine(Action onAllUnloaded)
        {
            var scenesToUnload = new List<string>(_loadedScenes);
            foreach (var sceneName in scenesToUnload)
            {
                yield return UnloadSceneCoroutine(sceneName, null);
            }
            onAllUnloaded?.Invoke();
        }
    }
}

using UnityEngine;

namespace Sttop5.Shared.Core
{
    /// <summary>
    /// 泛型单例基类，所有需要全局唯一实例的管理器继承此类。
    /// 自动处理 DontDestroyOnLoad 和重复实例销毁。
    /// </summary>
    public abstract class Singleton<T> : MonoBehaviour where T : MonoBehaviour
    {
        private static T _instance;
        private static readonly object _lock = new object();
        private static bool _applicationIsQuitting = false;

        public static T Instance
        {
            get
            {
                if (_applicationIsQuitting)
                {
                    return null;
                }

                lock (_lock)
                {
                    if (_instance == null)
                    {
                        _instance = FindObjectOfType<T>();

                        if (_instance == null)
                        {
                            GameObject go = new GameObject($"[Singleton] {typeof(T).Name}");
                            _instance = go.AddComponent<T>();
                            DontDestroyOnLoad(go);
                        }
                    }
                    return _instance;
                }
            }
        }

        protected virtual void Awake()
        {
            if (_instance == null)
            {
                _instance = this as T;
                transform.SetParent(null);
                DontDestroyOnLoad(gameObject);
            }
            else if (_instance != this)
            {
                Destroy(gameObject);
            }
        }

        protected virtual void OnDestroy()
        {
            if (_instance == this)
            {
                _applicationIsQuitting = true;
            }
        }

        /// <summary>
        /// 重置单例状态，仅用于测试或场景完全重载时。
        /// </summary>
        public static void ResetInstance()
        {
            _applicationIsQuitting = false;
            _instance = null;
        }
    }
}

