namespace TowerDefense.UI
{
    public class ShopPanel : MonoBehaviour
    {
        [Header("Panel")]
        [SerializeField] private GameObject _shopPanel;
        [SerializeField] private Button _closeButton;
        [SerializeField] private Image _dimOverlay;  // 半透明遮罩

        [Header("Currency Display")]
        [SerializeField] private Text _goldAmountText;
        [SerializeField] private Text _diamondAmountText;

        [Header("Tabs")]
        [SerializeField] private Button _tabResource;
        [SerializeField] private Button _tabHero;
        [SerializeField] private Button _tabTower;
        [SerializeField] private Button _tabSpecial;
        [SerializeField] private GameObject _tabIndicator;  // 滑动指示器
        [SerializeField] private Color _tabActiveColor = new Color(1f, 0.85f, 0.3f, 1f);
        [SerializeField] private Color _tabInactiveColor = new Color(0.6f, 0.6f, 0.6f, 1f);

        [Header("Content")]
        [SerializeField] private Transform _itemContainer;
        [SerializeField] private GameObject _shopItemPrefab;
        [Header("Confirm Dialog")]
        [SerializeField] private GameObject _confirmDialog;
        [SerializeField] private Text _confirmTitleText;
        [SerializeField] private Text _confirmDescText;
        [SerializeField] private Text _confirmPriceText;
        [SerializeField] private Button _confirmBuyButton;
        [SerializeField] private Button _confirmCancelButton;

        [Header("Feedback")]
        [SerializeField] private GameObject _feedbackPanel;
        [SerializeField] private Text _feedbackText;
        [SerializeField] private float _feedbackDuration = 1.5f;

        [Header("Data")]
        [SerializeField] private string _jsonPath = "Data/ShopItems";

        private ShopData _shopData;
        private ShopCategory _currentCategory;
        private ShopItemData _pendingBuyItem;
        private List<GameObject> _spawnedItems = new List<GameObject>();
        private Dictionary<ShopCategory, Button> _tabButtons = new Dictionary<ShopCategory, Button>();
        private Dictionary<ShopCategory, Vector3> _tabPositions = new Dictionary<ShopCategory, Vector3>();
        private GameObject _torchRoot;
        private MovingClouds _clouds;
        private ParticleSystem _snowParticles;
        private int _snowOriginalSortOrder;
        private Coroutine _feedbackCoroutine;

        private void Awake()
        {
            _tabButtons[ShopCategory.Resource] = _tabResource;
            _tabButtons[ShopCategory.Hero] = _tabHero;
            _tabButtons[ShopCategory.Tower] = _tabTower;
            _tabButtons[ShopCategory.Special] = _tabSpecial;

            if (_closeButton != null)
                _closeButton.onClick.AddListener(CloseShop);

            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value != null)
                {
                    var cat = kvp.Key;
                    kvp.Value.onClick.AddListener(() => SwitchTab(cat));
                    // 记录每个Tab的位置用于指示器滑动
                    _tabPositions[cat] = kvp.Value.transform.localPosition;
                }
            }

            // 确认弹窗按钮
            if (_confirmBuyButton != null)
                _confirmBuyButton.onClick.AddListener(OnConfirmBuy);
            if (_confirmCancelButton != null)
                _confirmCancelButton.onClick.AddListener(OnCancelBuy);

            _torchRoot = GameObject.Find("火把");

            GameObject bgObj = GameObject.Find("背景");
            if (bgObj != null)
            {
                _clouds = bgObj.GetComponent<MovingClouds>();
                _snowParticles = bgObj.GetComponentInChildren<ParticleSystem>();
                if (_snowParticles != null)
                {
                    var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                    if (renderer != null)
                        _snowOriginalSortOrder = renderer.sortingOrder;
                }
            }

            LoadShopData();
        }

        private void Start()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(false);
            if (_confirmDialog != null)
                _confirmDialog.SetActive(false);
            if (_feedbackPanel != null)
                _feedbackPanel.SetActive(false);
        }

        private void LoadShopData()
        {
            var jsonFile = Resources.Load<TextAsset>(_jsonPath);
            if (jsonFile != null)
            {
                _shopData = JsonUtility.FromJson<ShopData>(jsonFile.text);
                Debug.Log($"[ShopPanel] Loaded {_shopData.items.Length} items from JSON");
            }
            else
            {
                Debug.LogError($"[ShopPanel] Failed to load JSON: Resources/{_jsonPath}");
                _shopData = new ShopData { items = new ShopItemData[0] };
            }
        }

        public void OpenShop()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(true);

            // 半透明遮罩
            if (_dimOverlay != null)
            {
                _dimOverlay.gameObject.SetActive(true);
                _dimOverlay.color = new Color(0, 0, 0, 0.6f);
            }

            if (_torchRoot != null)
                _torchRoot.SetActive(false);

            if (_clouds != null)
                _clouds.IsPaused = true;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = -10;
                _snowParticles.Pause(true);
            }

            LoadShopData();
            UpdateCurrencyDisplay();
            SwitchTab(ShopCategory.Resource);
        }

        public void CloseShop()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(false);

            if (_dimOverlay != null)
                _dimOverlay.gameObject.SetActive(false);

            if (_torchRoot != null)
                _torchRoot.SetActive(true);

            if (_clouds != null)
                _clouds.IsPaused = false;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = _snowOriginalSortOrder;
                _snowParticles.Play(true);
            }
        }

        private void UpdateCurrencyDisplay()
        {
            var wallet = PlayerWallet.Instance;
            if (wallet != null)
            {
                if (_goldAmountText != null)
                    _goldAmountText.text = wallet.Gold.ToString();
                if (_diamondAmountText != null)
                    _diamondAmountText.text = wallet.Diamond.ToString();
            }
        }

        private void SwitchTab(ShopCategory category)
        {
            _currentCategory = category;
            UpdateTabVisuals();
            MoveTabIndicator(category);
            RefreshItemList();
        }

        private void UpdateTabVisuals()
        {
            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value == null) continue;
                var colors = kvp.Value.colors;
                colors.normalColor = kvp.Key == _currentCategory ? _tabActiveColor : _tabInactiveColor;
                colors.selectedColor = colors.normalColor;
                colors.highlightedColor = kvp.Key == _currentCategory ? _tabActiveColor : new Color(0.8f, 0.8f, 0.8f, 1f);
                kvp.Value.colors = colors;
            }
        }

        private void MoveTabIndicator(ShopCategory category)
        {
            if (_tabIndicator == null || !_tabPositions.ContainsKey(category)) return;
            StartCoroutine(AnimateTabIndicator(_tabPositions[category]));
        }

        private IEnumerator AnimateTabIndicator(Vector3 targetPos)
        {
            Vector3 startPos = _tabIndicator.transform.localPosition;
            float duration = 0.2f;
            float elapsed = 0f;

            while (elapsed < duration)
            {
                elapsed += Time.deltaTime;
                float t = elapsed / duration;
                // ease-out
                t = 1f - (1f - t) * (1f - t);
                _tabIndicator.transform.localPosition = Vector3.Lerp(startPos, targetPos, t);
                yield return null;
            }

            _tabIndicator.transform.localPosition = targetPos;
        }

        private void RefreshItemList()
        {
            foreach (var item in _spawnedItems)
            {
                if (item != null) Destroy(item);
            }
            _spawnedItems.Clear();

            if (_itemContainer == null || _shopItemPrefab == null)
            {
                Debug.LogWarning("[ShopPanel] Item container or prefab is null");
                return;
            }

            foreach (var itemData in _shopData.items)
            {
                if (itemData.category != _currentCategory) continue;

                GameObject itemObj = Instantiate(_shopItemPrefab, _itemContainer);
                _spawnedItems.Add(itemObj);

                var shopItemUI = itemObj.GetComponent<ShopItemUI>();
                if (shopItemUI != null)
                {
                    shopItemUI.Setup(itemData, this);
                }
            }
        }

        /// <summary>
        /// 点击购买时，先弹出确认框
        /// </summary>
        public void OnBuyClicked(ShopItemData itemData)
        {
            if (itemData.isLimited && itemData.purchasedCount >= itemData.limitCount)
            {
                ShowFeedback("已达购买上限!");
                return;
            }

            _pendingBuyItem = itemData;
            ShowConfirmDialog(itemData);
        }

        private void ShowConfirmDialog(ShopItemData itemData)
        {
            if (_confirmDialog == null)
            {
                // 没有确认弹窗则直接购买
                ExecuteBuy(itemData);
                return;
            }

            if (_confirmTitleText != null)
                _confirmTitleText.text = $"购买 {itemData.name}?";

            if (_confirmDescText != null)
            {
                string rewardText = ShopItemUI.BuildRewardText(itemData);
                _confirmDescText.text = string.IsNullOrEmpty(rewardText) ? itemData.description : $"获得: {rewardText}";
            }

            if (_confirmPriceText != null)
            {
                int price = itemData.discount > 0
                    ? itemData.price * (100 - itemData.discount) / 100
                    : itemData.price;

                if (itemData.currencyType == CurrencyType.Free)
                {
                    _confirmPriceText.text = "免费领取";
                    _confirmPriceText.color = Color.green;
                }
                else
                {
                    string symbol = GetCurrencySymbol(itemData.currencyType);
                    _confirmPriceText.text = $"花费: {symbol} {price}";
                    _confirmPriceText.color = Color.white;
                }
            }

            _confirmDialog.SetActive(true);
        }

        private void OnConfirmBuy()
        {
            if (_confirmDialog != null)
                _confirmDialog.SetActive(false);

            if (_pendingBuyItem != null)
            {
                ExecuteBuy(_pendingBuyItem);
                _pendingBuyItem = null;
            }
        }

        private void OnCancelBuy()
        {
            if (_confirmDialog != null)
                _confirmDialog.SetActive(false);
            _pendingBuyItem = null;
        }

        private void ExecuteBuy(ShopItemData itemData)
        {
            int price = itemData.discount > 0
                ? itemData.price * (100 - itemData.discount) / 100
                : itemData.price;

            var wallet = PlayerWallet.Instance;
            if (wallet == null)
            {
                Debug.LogWarning("[ShopPanel] PlayerWallet not found");
                return;
            }

            bool success = itemData.currencyType switch
            {
                CurrencyType.Gold => wallet.SpendGold(price),
                CurrencyType.Diamond => wallet.SpendDiamond(price),
                CurrencyType.Free => true,
                _ => false
            };

            if (!success)
            {
                string curName = itemData.currencyType switch
                {
                    CurrencyType.Gold => "金币不足",
                    CurrencyType.Diamond => "钻石不足",
                    _ => "无法购买"
                };
                ShowFeedback(curName);
                return;
            }

            Debug.Log($"[ShopPanel] 购买成功: {itemData.name}, 花费: {price}");

            // 发放奖励
            if (itemData.rewardGold > 0)
                wallet.AddGold(itemData.rewardGold);
            if (itemData.rewardDiamond > 0)
                wallet.AddDiamond(itemData.rewardDiamond);
            if (itemData.rewardStamina > 0)
                wallet.AddStamina(itemData.rewardStamina);

            itemData.purchasedCount++;

            ShowFeedback($"购买成功! {itemData.name}");
            UpdateCurrencyDisplay();
            RefreshItemList();
        }

        private void ShowFeedback(string message)
        {
            if (_feedbackPanel == null || _feedbackText == null) return;

            if (_feedbackCoroutine != null)
                StopCoroutine(_feedbackCoroutine);

            _feedbackCoroutine = StartCoroutine(ShowFeedbackCoroutine(message));
        }

        private IEnumerator ShowFeedbackCoroutine(string message)
        {
            _feedbackPanel.SetActive(true);
            _feedbackText.text = message;

            // 淡入
            var canvasGroup = _feedbackPanel.GetComponent<CanvasGroup>();
            if (canvasGroup != null)
            {
                canvasGroup.alpha = 0f;
                float fadeIn = 0.2f;
                float t = 0f;
                while (t < fadeIn)
                {
                    t += Time.deltaTime;
                    canvasGroup.alpha = Mathf.Lerp(0f, 1f, t / fadeIn);
                    yield return null;
                }
                canvasGroup.alpha = 1f;

                // 停留
                yield return new WaitForSeconds(_feedbackDuration);

                // 淡出
                float fadeOut = 0.3f;
                t = 0f;
                while (t < fadeOut)
                {
                    t += Time.deltaTime;
                    canvasGroup.alpha = Mathf.Lerp(1f, 0f, t / fadeOut);
                    yield return null;
                }
                canvasGroup.alpha = 0f;
            }
            else
            {
                yield return new WaitForSeconds(_feedbackDuration);
            }

            _feedbackPanel.SetActive(false);
            _feedbackCoroutine = null;
        }

        public static string GetCategoryName(ShopCategory category)
        {
            return category switch
            {
                ShopCategory.Resource => "资源",
                ShopCategory.Hero => "英雄",
                ShopCategory.Tower => "防御塔",
                ShopCategory.Special => "特惠",
                _ => "未知"
            };
        }

        public static string GetCurrencySymbol(CurrencyType type)
        {
            return type switch
            {
                CurrencyType.Gold => "🪙",
                CurrencyType.Diamond => "💎",
                CurrencyType.Free => "🎁",
                _ => ""
            };
        }
    }
}

using UnityEngine;
using TowerDefense.Tower;

public class BuildButtonManager : MonoBehaviour
{
    public static BuildButtonManager Instance { get; private set; }

    [Tooltip("建造按钮预制体")]
    public GameObject buildButtonPrefab;

    [Tooltip("Canvas引用")]
    public Canvas uiCanvas;

    [Tooltip("按钮偏移")]
    public Vector2 buttonOffset = new Vector2(0, 50);

    private GameObject _currentButton;
    private TowerSlot _currentSlot;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
        }
        else
        {
            Destroy(gameObject);
        }
    }

    private void Start()
    {
        if (uiCanvas == null)
        {
            uiCanvas = FindObjectOfType<Canvas>();
        }
    }

    /// <summary>
    /// 显示建造按钮
    /// </summary>
    public void ShowBuildButton(TowerSlot slot)
    {
        // 如果有其他按钮，先隐藏
        HideBuildButton();

        if (buildButtonPrefab == null || uiCanvas == null)
        {
            Debug.LogError("BuildButtonManager: Missing prefab or Canvas!");
            return;
        }

        // 计算按钮位置
        Vector3 worldPos = Camera.main.WorldToScreenPoint(slot.transform.position);
        worldPos += new Vector3(buttonOffset.x, buttonOffset.y, 0);

        // 实例化按钮
        _currentButton = Instantiate(buildButtonPrefab);
        _currentButton.transform.SetParent(uiCanvas.transform, false);
        _currentButton.transform.position = worldPos;

        // 绑定事件
        UnityEngine.UI.Button button = _currentButton.GetComponent<UnityEngine.UI.Button>();
        if (button != null)
        {
            button.onClick.AddListener(() => OnBuildButtonClicked(slot));
        }

        _currentSlot = slot;
        Debug.Log($"Build button shown for slot: {slot.name}");
    }

    /// <summary>
    /// 隐藏建造按钮
    /// </summary>
    public void HideBuildButton()
    {
        if (_currentButton != null)
        {
            Destroy(_currentButton);
            _currentButton = null;
        }
        _currentSlot = null;
    }

    /// <summary>
    /// 建造按钮点击
    /// </summary>
    private void OnBuildButtonClicked(TowerSlot slot)
    {
        Debug.Log("Build button clicked!");

        // 先隐藏按钮
        HideBuildButton();

        // 让槽位自己处理建造逻辑
        // 这里我们直接调用一个方法
        slot.OnBuildButtonClickedByManager();
    }

    /// <summary>
    /// 检查当前是否显示了按钮
    /// </summary>
    public bool IsButtonShowing()
    {
        return _currentButton != null;
    }
}

using UnityEngine;

namespace TowerDefense.Utils
{
    public static class MathUtils
    {
        public static float Remap(float value, float fromMin, float fromMax, float toMin, float toMax)
        {
            return toMin + (value - fromMin) * (toMax - toMin) / (fromMax - fromMin);
        }

        public static float ClampAngle(float angle)
        {
            if (angle < 0) angle += 360f;
            if (angle >= 360) angle -= 360f;
            return angle;
        }

        public static Vector2 RotateVector2(Vector2 v, float degrees)
        {
            float sin = Mathf.Sin(degrees * Mathf.Deg2Rad);
            float cos = Mathf.Cos(degrees * Mathf.Deg2Rad);
            return new Vector2(cos * v.x - sin * v.y, sin * v.x + cos * v.y);
        }

        public static float DistanceToLine(Vector3 point, Vector3 lineStart, Vector3 lineEnd)
        {
            Vector3 line = lineEnd - lineStart;
            float len = line.magnitude;
            line.Normalize();

            Vector3 v = point - lineStart;
            float d = Vector3.Dot(v, line);
            d = Mathf.Clamp(d, 0f, len);

            Vector3 closestPoint = lineStart + line * d;
            return Vector3.Distance(point, closestPoint);
        }
    }

    public static class TransformExtensions
    {
        public static void DestroyChildren(this Transform transform)
        {
            for (int i = transform.childCount - 1; i >= 0; i--)
            {
                Object.Destroy(transform.GetChild(i).gameObject);
            }
        }

        public static void SetLayerRecursively(this Transform transform, int layer)
        {
            transform.gameObject.layer = layer;
            foreach (Transform child in transform)
            {
                child.SetLayerRecursively(layer);
            }
        }
    }

    public static class ColorUtils
    {
        public static Color WithAlpha(this Color color, float alpha)
        {
            return new Color(color.r, color.g, color.b, alpha);
        }

        public static string ColorToHex(Color color)
        {
            return $"#{(int)(color.r * 255):X2}{(int)(color.g * 255):X2}{(int)(color.b * 255):X2}";
        }

        public static Color HexToColor(string hex)
        {
            if (hex.StartsWith("#"))
                hex = hex.Substring(1);

            byte r = byte.Parse(hex.Substring(0, 2), System.Globalization.NumberStyles.HexNumber);
            byte g = byte.Parse(hex.Substring(2, 2), System.Globalization.NumberStyles.HexNumber);
            byte b = byte.Parse(hex.Substring(4, 2), System.Globalization.NumberStyles.HexNumber);

            return new Color32(r, g, b, 255);
        }
    }

    public static class ArrayUtils
    {
        public static T GetRandomElement<T>(T[] array)
        {
            if (array == null || array.Length == 0)
                return default;
            return array[Random.Range(0, array.Length)];
        }

        public static T[] Shuffle<T>(T[] array)
        {
            T[] result = (T[])array.Clone();
            for (int i = result.Length - 1; i > 0; i--)
            {
                int j = Random.Range(0, i + 1);
                T temp = result[i];
                result[i] = result[j];
                result[j] = temp;
            }
            return result;
        }
    }
}

using System.Collections.Generic;
using UnityEngine;

namespace TowerDefense.Utils
{
    public class PathCreator : MonoBehaviour
    {
        [Header("Path Settings")]
        [SerializeField] private List<Vector3> _waypoints = new List<Vector3>();
        [SerializeField] private Color _pathColor = Color.red;
        [SerializeField] private float _waypointRadius = 0.3f;
        [SerializeField] private bool _showPath = true;

        [Header("Editing")]
        [SerializeField] private bool _editingMode = false;
        [SerializeField] private int _selectedWaypoint = -1;

        public List<Vector3> Waypoints => _waypoints;
        public int WaypointCount => _waypoints.Count;

        public void AddWaypoint(Vector3 position)
        {
            _waypoints.Add(position);
        }

        public void AddWaypointAtMouse()
        {
            Vector3 mousePos = Camera.main.ScreenToWorldPoint(Input.mousePosition);
            mousePos.z = 0;
            AddWaypoint(mousePos);
        }

        public void RemoveWaypoint(int index)
        {
            if (index >= 0 && index < _waypoints.Count)
            {
                _waypoints.RemoveAt(index);
            }
        }

        public void ClearPath()
        {
            _waypoints.Clear();
        }

        public void MoveWaypoint(int index, Vector3 newPosition)
        {
            if (index >= 0 && index < _waypoints.Count)
            {
                _waypoints[index] = newPosition;
            }
        }

        public void InsertWaypoint(int index, Vector3 position)
        {
            if (index >= 0 && index <= _waypoints.Count)
            {
                _waypoints.Insert(index, position);
            }
        }

        public Vector3 GetWaypoint(int index)
        {
            if (index >= 0 && index < _waypoints.Count)
            {
                return _waypoints[index];
            }
            return Vector3.zero;
        }

        public float GetTotalDistance()
        {
            float distance = 0f;
            for (int i = 1; i < _waypoints.Count; i++)
            {
                distance += Vector3.Distance(_waypoints[i - 1], _waypoints[i]);
            }
            return distance;
        }

        public List<Vector3> GetSmoothPath(int subdivisions = 10)
        {
            if (_waypoints.Count < 2) return new List<Vector3>(_waypoints);

            List<Vector3> smoothPath = new List<Vector3>();

            for (int i = 0; i < _waypoints.Count - 1; i++)
            {
                Vector3 start = _waypoints[i];
                Vector3 end = _waypoints[i + 1];

                for (int j = 0; j < subdivisions; j++)
                {
                    float t = j / (float)subdivisions;
                    smoothPath.Add(Vector3.Lerp(start, end, t));
                }
            }

            smoothPath.Add(_waypoints[_waypoints.Count - 1]);

            return smoothPath;
        }

        private void OnDrawGizmos()
        {
            if (!_showPath || _waypoints.Count == 0) return;

            Gizmos.color = _pathColor;

            for (int i = 0; i < _waypoints.Count - 1; i++)
            {
                Gizmos.DrawLine(_waypoints[i], _waypoints[i + 1]);
            }

            for (int i = 0; i < _waypoints.Count; i++)
            {
                Gizmos.color = i == _selectedWaypoint ? Color.yellow : _pathColor;
                Gizmos.DrawWireSphere(_waypoints[i], _waypointRadius);

#if UNITY_EDITOR
                UnityEditor.Handles.Label(_waypoints[i] + Vector3.up * 0.5f, i.ToString());
#endif
            }

            if (_waypoints.Count > 0)
            {
                Gizmos.color = Color.green;
                Gizmos.DrawSphere(_waypoints[0], _waypointRadius * 1.2f);

                Gizmos.color = Color.red;
                Gizmos.DrawSphere(_waypoints[_waypoints.Count - 1], _waypointRadius * 1.2f);
            }
        }
    }
}

using UnityEngine;
using System.Collections.Generic;

public class PathSystem : MonoBehaviour
{
    [Header("Path Settings")]
    [SerializeField] private Transform[] _waypoints;
    [SerializeField] private bool _isClosedLoop = false;
    [SerializeField] private Color _pathColor = Color.cyan;
    
    public int WaypointCount => _waypoints.Length;
    
    private void Awake()
    {
        if (_waypoints == null || _waypoints.Length == 0)
        {
            Debug.LogWarning("No waypoints assigned to PathSystem!");
        }
    }
    
    public Vector3 GetWaypoint(int index)
    {
        if (_waypoints == null || index < 0 || index >= _waypoints.Length)
        {
            return Vector3.zero;
        }
        return _waypoints[index].position;
    }
    
    public Vector3[] GetAllWaypoints()
    {
        if (_waypoints == null) return new Vector3[0];
        
        Vector3[] points = new Vector3[_waypoints.Length];
        for (int i = 0; i < _waypoints.Length; i++)
        {
            points[i] = _waypoints[i].position;
        }
        return points;
    }
    
    public Vector3 GetStartPoint()
    {
        return GetWaypoint(0);
    }
    
    public Vector3 GetEndPoint()
    {
        return GetWaypoint(_waypoints.Length - 1);
    }
    
    private void OnDrawGizmos()
    {
        if (_waypoints == null || _waypoints.Length < 2) return;
        
        Gizmos.color = _pathColor;
        
        for (int i = 0; i < _waypoints.Length - 1; i++)
        {
            Gizmos.DrawLine(_waypoints[i].position, _waypoints[i + 1].position);
        }
        
        if (_isClosedLoop && _waypoints.Length > 1)
        {
            Gizmos.DrawLine(_waypoints[_waypoints.Length - 1].position, _waypoints[0].position);
        }
        
        Gizmos.color = Color.red;
        foreach (var waypoint in _waypoints)
        {
            Gizmos.DrawSphere(waypoint.position, 0.2f);
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using System.Collections;
using System.Collections.Generic;
using TowerDefense.Data;
using TowerDefense.Enemy;
using TowerDefense.Core;

namespace TowerDefense.Wave
{
    public class WaveManager : MonoBehaviour
    {
        public static WaveManager Instance { get; private set; }

        [Header("Settings")]
        [SerializeField] private EnemySpawner _enemySpawner;
        [SerializeField] private float _waveDelay = 5f;
        [SerializeField] private int _totalWaves = 5;
        [SerializeField] private int _baseEnemyCount = 5;
        [SerializeField] private int _enemyIncreasePerWave = 2;

        [Header("Wave Data (Optional)")]
        [Tooltip("如果设置了这个数组，将使用这里的配置而不是动态生成")]
        [SerializeField] private WaveData[] _waveDatas;

        [Header("Enemy Data")]
        [Tooltip("所有可用的敌人数据（飞机、骷髅等）")]
        [SerializeField] private EnemyData[] _enemyDatas;

        private EnemyData _defaultEnemyData;

        [Header("UI")]
        [SerializeField] private Text _waveText;
        [SerializeField] private Text _enemyCountText;
        [SerializeField] private Text _waveAnnounceText;
        [SerializeField] private float _announceDuration = 2f;

        private int _currentWaveIndex = 0;
        private float _waveTimer = 0f;
        private bool _isWaveActive = false;
        private bool _isWaveTransition = false;

        public int CurrentWave => _currentWaveIndex;
        public int TotalWaves => _totalWaves;
        public bool IsWaveActive => _isWaveActive;

        private void Awake()
        {
            if (Instance == null)
            {
                Instance = this;
            }
            else
            {
                Destroy(gameObject);
            }
        }

        private void Start()
        {
            LoadEnemyData();
            UpdateWaveUI();

            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.gameObject.SetActive(false);
            }

            EventBus.Subscribe<GameStartEvent>(OnGameStart);
        }

        private void LoadEnemyData()
        {
            // 如果在 Inspector 中设置了敌人数据数组，直接使用
            if (_enemyDatas != null && _enemyDatas.Length > 0)
            {
                Debug.Log($"已加载 {_enemyDatas.Length} 个敌人数据");
                foreach (var enemy in _enemyDatas)
                {
                    Debug.Log($"  - {enemy.enemyName}");
                }
                // 使用第一个作为默认
                _defaultEnemyData = _enemyDatas[0];
                return;
            }

            // 否则尝试从 Resources 加载
            _defaultEnemyData = Resources.Load<EnemyData>("Data/EnemyData");
            if (_defaultEnemyData == null)
            {
                Debug.LogError("Failed to load EnemyData from Resources/Data/EnemyData");
            }
        }

        private void OnDestroy()
        {
            EventBus.Unsubscribe<GameStartEvent>(OnGameStart);
        }

        private void OnGameStart(GameStartEvent e)
        {
            ForceStartWave();
        }

        private void Update()
        {
            if (_isWaveTransition && !_isWaveActive)
            {
                _waveTimer += Time.deltaTime;

                float remainingTime = _waveDelay - _waveTimer;

                if (remainingTime > 0)
                {
                    UpdateWaveCountdown((int)Mathf.CeilToInt(remainingTime));
                }

                if (remainingTime % 1f < 0.05f)
                {
                    Debug.Log($"倒计时更新: timer={_waveTimer:F1}/{_waveDelay}, 剩余={remainingTime:F1}s, transition={_isWaveTransition}, active={_isWaveActive}");
                }

                if (_waveTimer >= _waveDelay)
                {
                    Debug.Log($"✅ 倒计时结束, 准备开始下一波!");
                    _waveTimer = 0f;
                    HideWaveCountdown();
                    StartNextWave();
                }
            }

            UpdateEnemyCountDisplay();
        }

        private void UpdateWaveCountdown(int seconds)
        {
            if (_waveAnnounceText != null)
            {
                int nextWave = _currentWaveIndex + 1;
                _waveAnnounceText.text = $"第 {nextWave} 波 {seconds} 秒后出现！";
                _waveAnnounceText.gameObject.SetActive(true);
            }
        }

        private void HideWaveCountdown()
        {
            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.gameObject.SetActive(false);
            }
        }

        private void UpdateEnemyCountDisplay()
        {
            if (_enemyCountText != null)
            {
                // 用 EnemySpawner 追踪的波次剩余敌人（出生总数 - 死亡数）
                _enemyCountText.text = $"剩余敌人:{TowerDefense.Enemy.EnemySpawner.RemainingEnemies}";
            }
        }

        public void StartNextWave()
        {
            if (_currentWaveIndex >= _totalWaves)
            {
                Debug.Log("All waves completed!");
                if (GameManager.Instance != null)
                {
                    GameManager.Instance.OnVictory();
                }
                return;
            }

            // 先增加波次索引
            _currentWaveIndex++;

            WaveData waveData = GetWaveData();
            if (waveData == null)
            {
                Debug.LogError("Failed to get wave data!");
                return;
            }

            _enemySpawner.StartWave(waveData);

            _isWaveActive = true;
            _isWaveTransition = false;

            if (GameManager.Instance != null)
            {
                GameManager.Instance.SetCurrentWave(_currentWaveIndex);
            }

            EventBus.Publish(new WaveStartEvent { WaveIndex = _currentWaveIndex });

            UpdateWaveUI();
            StartCoroutine(ShowWaveAnnouncement(_currentWaveIndex));
            Debug.Log($"Starting wave {_currentWaveIndex}");
        }

        private IEnumerator ShowWaveAnnouncement(int waveNumber)
        {
            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.text = $"第 {waveNumber} 波开始出怪！";
                _waveAnnounceText.gameObject.SetActive(true);

                Debug.Log($"📢 {_waveAnnounceText.text}");

                yield return new WaitForSeconds(_announceDuration);

                _waveAnnounceText.gameObject.SetActive(false);
            }
        }

        private WaveData GetWaveData()
        {
            // 如果用户设置了 WaveData 数组，使用它
            if (_waveDatas != null && _waveDatas.Length > 0)
            {
                int index = _currentWaveIndex - 1;
                if (index >= 0 && index < _waveDatas.Length)
                {
                    Debug.Log($"使用配置的 WaveData: 波次 {_currentWaveIndex}");
                    return _waveDatas[index];
                }
            }

            // 否则动态生成
            if (_defaultEnemyData == null && (_enemyDatas == null || _enemyDatas.Length == 0))
            {
                Debug.LogError("No EnemyData available! Cannot create wave data.");
                return null;
            }

            Debug.Log($"动态生成 WaveData: 波次 {_currentWaveIndex}");
            return CreateWaveData();
        }

        private WaveData CreateWaveData()
        {
            WaveData waveData = ScriptableObject.CreateInstance<WaveData>();
            waveData.waveNumber = _currentWaveIndex;
            waveData.spawnInterval = Mathf.Max(0.5f, 1.5f - (_currentWaveIndex - 1) * 0.1f);
            waveData.enemies = new List<WaveData.WaveEnemy>();

            int totalEnemies = _baseEnemyCount + (_currentWaveIndex - 1) * _enemyIncreasePerWave;

            // 使用多个敌人数据
            if (_enemyDatas != null && _enemyDatas.Length > 0)
            {
                // 随机选择敌人
                for (int i = 0; i < _enemyDatas.Length; i++)
                {
                    int enemyCount = totalEnemies / _enemyDatas.Length;
                    if (i == 0)
                    {
                        enemyCount += totalEnemies % _enemyDatas.Length;
                    }

                    if (enemyCount > 0)
                    {
                        waveData.enemies.Add(new WaveData.WaveEnemy
                        {
                            enemyData = _enemyDatas[i],
                            count = enemyCount,
                            spawnDelay = 0,
                            spawnPoint = "MainPath"
                        });

                        Debug.Log($"波次 {_currentWaveIndex} 添加 {enemyCount} 个 {_enemyDatas[i].enemyName}");
                    }
                }
            }
            else
            {
                // 只有一个敌人数据时使用旧方法
                waveData.enemies.Add(new WaveData.WaveEnemy
                {
                    enemyData = _defaultEnemyData,
                    count = totalEnemies,
                    spawnDelay = 0,
                    spawnPoint = "MainPath"
                });
            }

            return waveData;
        }

        public void OnWaveComplete()
        {
            _isWaveActive = false;

            Debug.Log($"波次 {_currentWaveIndex}/{_totalWaves} 完成!");
            EventBus.Publish(new WaveEndEvent { WaveIndex = _currentWaveIndex });

            if (_currentWaveIndex >= _totalWaves)
            {
                Debug.Log($"全部波次完成!");
                if (GameManager.Instance != null)
                {
                    GameManager.Instance.OnVictory();
                }
            }
            else
            {
                _isWaveTransition = true;
                _waveTimer = 0f;
            }

            UpdateWaveUI();
        }

        public void StartWaveManually(int waveIndex)
        {
            if (waveIndex >= 0 && waveIndex < _totalWaves)
            {
                _currentWaveIndex = waveIndex;
                StartNextWave();
            }
        }

        public void SkipToNextWave()
        {
            if (!_isWaveActive && _currentWaveIndex < _totalWaves)
            {
                StartNextWave();
            }
        }

        public void ForceStartWave()
        {
            if (!_isWaveActive)
            {
                _isWaveTransition = false;
                _waveTimer = 0f;
                StartNextWave();
            }
        }

        private void UpdateWaveUI()
        {
            if (_waveText != null)
            {
                _waveText.text = $"波次:{_currentWaveIndex}/{_totalWaves}";
            }

            UpdateEnemyCountDisplay();
        }

        public void Reset()
        {
            _currentWaveIndex = 0;
            _waveTimer = 0f;
            _isWaveActive = false;
            _isWaveTransition = false;
            UpdateWaveUI();
        }
    }
}

using UnityEngine;
using UnityEditor;
using TowerDefense.Utils;

namespace TowerDefense.Editor
{
    [CustomEditor(typeof(PathCreator))]
    public class PathCreatorEditor : UnityEditor.Editor
    {
        private PathCreator _pathCreator;
        private int _selectedWaypoint = -1;
        private bool _editingPath = false;

        private void OnEnable()
        {
            _pathCreator = (PathCreator)target;
        }

        public override void OnInspectorGUI()
        {
            base.OnInspectorGUI();

            EditorGUILayout.Space(10);
            EditorGUILayout.LabelField("Path Tools", EditorStyles.boldLabel);

            EditorGUILayout.BeginHorizontal();

            if (GUILayout.Button("Add Waypoint"))
            {
                Vector3 newPos = _pathCreator.WaypointCount > 0
                    ? _pathCreator.GetWaypoint(_pathCreator.WaypointCount - 1) + Vector3.right
                    : _pathCreator.transform.position;
                _pathCreator.AddWaypoint(newPos);
                EditorUtility.SetDirty(_pathCreator);
            }

            if (GUILayout.Button("Clear Path"))
            {
                _pathCreator.ClearPath();
                EditorUtility.SetDirty(_pathCreator);
            }

            EditorGUILayout.EndHorizontal();

            EditorGUILayout.BeginHorizontal();

            if (GUILayout.Button("Smooth Path"))
            {
            }

            if (GUILayout.Button("Reverse Path"))
            {
                EditorUtility.SetDirty(_pathCreator);
            }

            EditorGUILayout.EndHorizontal();

            EditorGUILayout.Space(5);
            EditorGUILayout.LabelField($"Waypoints: {_pathCreator.WaypointCount}");
            EditorGUILayout.LabelField($"Total Distance: {_pathCreator.GetTotalDistance():F2}");

            _editingPath = EditorGUILayout.Toggle("Edit Mode", _editingPath);

            if (_editingPath)
            {
                EditorGUILayout.HelpBox("Click in Scene to add waypoints. Shift+Click to remove.", MessageType.Info);
            }
        }

        private void OnSceneGUI()
        {
            if (!_editingPath) return;

            Event e = Event.current;

            if (e.type == EventType.MouseDown && e.button == 0)
            {
                Ray ray = HandleUtility.GUIPointToWorldRay(e.mousePosition);
                Vector3 mousePos = ray.origin;
                mousePos.z = 0;

                if (e.shift)
                {
                    if (_pathCreator.WaypointCount > 0)
                    {
                        _pathCreator.RemoveWaypoint(_pathCreator.WaypointCount - 1);
                    }
                }
                else
                {
                    _pathCreator.AddWaypoint(mousePos);
                }

                EditorUtility.SetDirty(_pathCreator);
                e.Use();
            }

            Handles.color = Color.yellow;
            for (int i = 0; i < _pathCreator.WaypointCount; i++)
            {
                Vector3 waypoint = _pathCreator.GetWaypoint(i);

                EditorGUI.BeginChangeCheck();
                var fmh_106_21_639139147708220621 = Quaternion.identity; Vector3 newWaypoint = Handles.FreeMoveHandle(
                    waypoint,
                    0.3f,
                    Vector3.zero,
                    Handles.CylinderHandleCap
                );

                if (EditorGUI.EndChangeCheck())
                {
                    Undo.RecordObject(_pathCreator, "Move Waypoint");
                    _pathCreator.MoveWaypoint(i, newWaypoint);
                    EditorUtility.SetDirty(_pathCreator);
                }
            }
        }
    }
}

using System;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Save;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 家园主控制器，管理家园场景的初始化和生命周期。
    /// 作为 GameModule 注册到 ModuleManager。
    /// </summary>
    public class HomeManager : GameModule
    {
        private const string MODULE_ID = "home";
        private const string MODULE_DISPLAY_NAME = "家园";
        private const string SAVE_KEY = "homebase";

        [Header("组件引用")]
        [SerializeField] private BuildingManager _buildingManager;
        [SerializeField] private ResourceManager _resourceManager;

        [Header("初始建筑")]
        [SerializeField] private BuildingData[] _starterBuildings;
        [SerializeField] private Vector3[] _starterPositions;

        private bool _isLoaded = false;

        private void Awake()
        {
            _moduleId = MODULE_ID;
            _displayName = MODULE_DISPLAY_NAME;
            _sceneName = gameObject.scene.name;
        }

        private void Start()
        {
            InitializeHome();
        }

        private void InitializeHome()
        {
            if (_isLoaded) return;

            // 注册到 ModuleManager
            var moduleManager = ModuleManager.Instance;
            if (moduleManager != null)
            {
                moduleManager.RegisterModule(this);
            }

            // 尝试从存档加载
            LoadHomeSave();

            // 如果没有建筑，放置初始建筑
            if (_buildingManager.Buildings.Count == 0)
            {
                PlaceStarterBuildings();
            }

            _isLoaded = true;
            Debug.Log("[HomeManager] 家园初始化完成");
        }

        private void PlaceStarterBuildings()
        {
            if (_starterBuildings == null || _starterPositions == null) return;

            int count = Mathf.Min(_starterBuildings.Length, _starterPositions.Length);
            for (int i = 0; i < count; i++)
            {
                if (_starterBuildings[i] != null)
                {
                    _buildingManager.PlaceBuilding(_starterBuildings[i], _starterPositions[i]);
                }
            }

            Debug.Log($"[HomeManager] 放置 {count} 个初始建筑");
        }

        #region 存档

        public override string GetModuleSaveData()
        {
            var saveData = new HomeSaveData();
            _resourceManager?.SaveToSave(saveData);
            saveData.buildings = _buildingManager?.ExportSaveData();
            return JsonUtility.ToJson(saveData);
        }

        public override void RestoreModuleSaveData(string jsonData)
        {
            if (string.IsNullOrEmpty(jsonData)) return;

            try
            {
                var saveData = JsonUtility.FromJson<HomeSaveData>(jsonData);
                _resourceManager?.LoadFromSave(saveData);
                _buildingManager?.RestoreFromSaveData(saveData.buildings);
            }
            catch (Exception e)
            {
                Debug.LogError($"[HomeManager] 恢复存档失败: {e.Message}");
            }
        }

        private void LoadHomeSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null) return;

            string json = saveSystem.LoadModuleData(SAVE_KEY);
            if (!string.IsNullOrEmpty(json))
            {
                RestoreModuleSaveData(json);
                Debug.Log("[HomeManager] 家园存档已加载");
            }
        }

        private void SaveHomeData()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null) return;

            string json = GetModuleSaveData();
            saveSystem.SaveModuleData(SAVE_KEY, json, 1);
        }

        #endregion

        #region 模块生命周期

        public override void Activate()
        {
            base.Activate();
            Debug.Log("[HomeManager] 家园已激活");
        }

        public override void Deactivate()
        {
            SaveHomeData();
            base.Deactivate();
            Debug.Log("[HomeManager] 家园已停用");
        }

        #endregion

        #region 按钮回调

        /// <summary>
        /// 收集所有资源按钮回调。
        /// </summary>
        public void OnCollectAllClicked()
        {
            _resourceManager?.CollectAllResources();
        }

        #endregion

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) SaveHomeData();
        }

        private void OnApplicationQuit()
        {
            SaveHomeData();
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using Sttop5.Shared.Core;
