    }
}

using UnityEngine;
using UnityEngine.UI;
using System.Collections.Generic;
using System.Linq;
using TowerDefense.Data;

namespace TowerDefense.UI
{
    public class AchievementPanel : MonoBehaviour
    {
        [Header("Panel")]
        [SerializeField] private GameObject _panel;
        [SerializeField] private Button _closeButton;

        [Header("Header")]
        [SerializeField] private Text _titleText;
        [SerializeField] private Text _totalCountText;
        [SerializeField] private Slider _totalProgressSlider;
        [SerializeField] private Text _totalPercentText;

        [Header("Milestones")]
        [SerializeField] private Transform _milestoneContainer;
        [SerializeField] private GameObject _milestonePrefab;

        [Header("Tabs")]
        [SerializeField] private Button _tabAll;
        [SerializeField] private Button _tabGrowth;
        [SerializeField] private Button _tabBattle;
        [SerializeField] private Button _tabCollection;
        [SerializeField] private Button _tabExploration;
        [SerializeField] private Button _tabFun;
        [SerializeField] private Color _tabActiveColor = new Color(0.45f, 0.75f, 0.3f, 1f);
        [SerializeField] private Color _tabInactiveColor = new Color(0.95f, 0.93f, 0.85f, 1f);

        [Header("Content")]
        [SerializeField] private Transform _itemContainer;
        [SerializeField] private GameObject _achievementItemPrefab;

        [Header("Claim All")]
        [SerializeField] private Button _claimAllButton;

        [Header("Data")]
        [SerializeField] private string _jsonPath = "Data/Achievements";

        private AchievementData _data;
        private bool _isOpen;
        private AchievementCategory _currentCategory = AchievementCategory.All;
        private List<GameObject> _spawnedItems = new List<GameObject>();
        private Dictionary<AchievementCategory, Button> _tabButtons = new Dictionary<AchievementCategory, Button>();
        private GameObject _torchRoot;
        private MovingClouds _clouds;
        private ParticleSystem _snowParticles;
        private int _snowOriginalSortOrder;

        private void Awake()
        {
            _tabButtons[AchievementCategory.All] = _tabAll;
            _tabButtons[AchievementCategory.Growth] = _tabGrowth;
            _tabButtons[AchievementCategory.Battle] = _tabBattle;
            _tabButtons[AchievementCategory.Collection] = _tabCollection;
            _tabButtons[AchievementCategory.Exploration] = _tabExploration;
            _tabButtons[AchievementCategory.Fun] = _tabFun;

            if (_closeButton != null)
                _closeButton.onClick.AddListener(ClosePanel);

            if (_claimAllButton != null)
                _claimAllButton.onClick.AddListener(ClaimAll);

            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value != null)
                {
                    var cat = kvp.Key;
                    kvp.Value.onClick.AddListener(() => SwitchTab(cat));
                }
            }

            _torchRoot = GameObject.Find("火把");
            GameObject bgObj = GameObject.Find("背景");
            if (bgObj != null)
            {
                _clouds = bgObj.GetComponent<MovingClouds>();
                _snowParticles = bgObj.GetComponentInChildren<ParticleSystem>();
                if (_snowParticles != null)
                {
                    var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                    if (renderer != null)
                        _snowOriginalSortOrder = renderer.sortingOrder;
                }
            }

            LoadData();
        }

        private void Start()
        {
            // 首次启动时隐藏面板，但避免在 OpenPanel 调用后误关
            if (_panel != null && !_isOpen)
                _panel.SetActive(false);
        }

        private void LoadData()
        {
            var jsonFile = Resources.Load<TextAsset>(_jsonPath);
            if (jsonFile != null)
            {
                _data = JsonUtility.FromJson<AchievementData>(jsonFile.text);
                Debug.Log($"[AchievementPanel] Loaded {_data.items.Length} achievements");
            }
            else
            {
                Debug.LogError($"[AchievementPanel] Failed to load: Resources/{_jsonPath}");
                _data = new AchievementData { items = new AchievementItemData[0] };
            }
        }

        public void OpenPanel()
        {
            _isOpen = true;
            if (_panel != null)
                _panel.SetActive(true);

            if (_torchRoot != null) _torchRoot.SetActive(false);
            if (_clouds != null) _clouds.IsPaused = true;
            if (_snowParticles != null)
            {
                var r = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (r != null) r.sortingOrder = -10;
                _snowParticles.Pause(true);
            }

            LoadData();
            UpdateHeader();
            SwitchTab(AchievementCategory.All);
        }

        public void ClosePanel()
        {
            _isOpen = false;
            if (_panel != null)
                _panel.SetActive(false);

            if (_torchRoot != null) _torchRoot.SetActive(true);
            if (_clouds != null) _clouds.IsPaused = false;
            if (_snowParticles != null)
            {
                var r = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (r != null) r.sortingOrder = _snowOriginalSortOrder;
                _snowParticles.Play(true);
            }
        }

        private void SwitchTab(AchievementCategory category)
        {
            _currentCategory = category;
            UpdateTabVisuals();
            RefreshItemList();
        }

        private void UpdateTabVisuals()
        {
            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value == null) continue;
                var colors = kvp.Value.colors;
                colors.normalColor = kvp.Key == _currentCategory ? _tabActiveColor : _tabInactiveColor;
                colors.selectedColor = colors.normalColor;
                colors.highlightedColor = kvp.Key == _currentCategory
                    ? _tabActiveColor
                    : new Color(0.85f, 0.83f, 0.75f, 1f);
                kvp.Value.colors = colors;
            }
        }

        private void UpdateHeader()
        {
            if (_data == null) return;

            int total = _data.items.Length;
            int completed = _data.items.Count(i => i.status == AchievementStatus.Claimed);
            float pct = total > 0 ? (float)completed / total : 0f;

            if (_totalCountText != null)
                _totalCountText.text = $"{completed}/{total}";

            if (_totalProgressSlider != null)
            {
                _totalProgressSlider.maxValue = total;
                _totalProgressSlider.value = completed;
            }

            if (_totalPercentText != null)
                _totalPercentText.text = $"{(int)(pct * 100)}%";

            // 一键领取按钮
            if (_claimAllButton != null)
            {
                bool hasClaimable = _data.items.Any(i => i.status == AchievementStatus.Claimable);
                _claimAllButton.interactable = hasClaimable;
            }
        }

        private void RefreshItemList()
        {
            foreach (var item in _spawnedItems)
            {
                if (item != null) DestroyImmediate(item);
            }
            _spawnedItems.Clear();

            if (_itemContainer == null || _achievementItemPrefab == null) return;

            var items = _data.items
                .Where(i => _currentCategory == AchievementCategory.All || i.category == _currentCategory)
                .OrderBy(i => (int)i.status)
                .ThenBy(i => i.sortIndex);

            foreach (var itemData in items)
            {
                GameObject itemObj = Instantiate(_achievementItemPrefab, _itemContainer);
                itemObj.SetActive(true);
                _spawnedItems.Add(itemObj);

                var ui = itemObj.GetComponent<AchievementItemUI>();
                if (ui != null)
                    ui.Setup(itemData, this);
            }
        }

        public void OnClaimClicked(AchievementItemData itemData)
        {
            if (itemData.status != AchievementStatus.Claimable) return;

            var wallet = PlayerWallet.Instance;
            if (wallet == null) return;

            GrantRewards(itemData.rewards);

            itemData.status = AchievementStatus.Claimed;
            Debug.Log($"[AchievementPanel] 领取: {itemData.name}");

            UpdateHeader();
            RefreshItemList();
        }

        private void ClaimAll()
        {
            var wallet = PlayerWallet.Instance;
            if (wallet == null) return;

            var claimable = _data.items.Where(i => i.status == AchievementStatus.Claimable).ToList();
            if (claimable.Count == 0) return;

            foreach (var item in claimable)
            {
                GrantRewards(item.rewards);
                item.status = AchievementStatus.Claimed;
            }

            Debug.Log($"[AchievementPanel] 一键领取 {claimable.Count} 个成就");
            UpdateHeader();
            RefreshItemList();
        }

        private void GrantRewards(AchievementReward[] rewards)
        {
            if (rewards == null) return;
            var wallet = PlayerWallet.Instance;
            foreach (var r in rewards)
            {
                switch (r.rewardType)
                {
                    case RewardType.Gold: wallet?.AddGold(r.amount); break;
                    case RewardType.Diamond: wallet?.AddDiamond(r.amount); break;
                    case RewardType.Stamina: wallet?.AddStamina(r.amount); break;
                    case RewardType.Exp: PlayerLevelSystem.Instance?.AddExp(r.amount); break;
                }
            }
        }

        public void UpdateAchievementProgress(int id, int currentCount)
        {
            if (_data == null) return;
            var item = _data.items.FirstOrDefault(i => i.id == id);
            if (item == null) return;

            item.currentCount = currentCount;
            if (item.currentCount >= item.targetCount && item.status == AchievementStatus.InProgress)
            {
                item.status = AchievementStatus.Claimable;
                Debug.Log($"[AchievementPanel] 成就可领取: {item.name}");
            }
        }

        public static string GetCategoryName(AchievementCategory cat)
        {
            return cat switch
            {
                AchievementCategory.All => "全部",
                AchievementCategory.Growth => "成长",
                AchievementCategory.Battle => "战斗",
                AchievementCategory.Collection => "收集",
                AchievementCategory.Exploration => "探索",
                AchievementCategory.Fun => "趣味",
                _ => "未知"
            };
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using System.Collections.Generic;
using TowerDefense.Data;
using TowerDefense.Save;

namespace TowerDefense.UI
{
    public class QuestPanel : MonoBehaviour
    {
        [Header("Panel")]
        [SerializeField] private GameObject _questPanel;
        [SerializeField] private Button _closeButton;

        [Header("Tabs")]
        [SerializeField] private Button _tabDaily;
        [SerializeField] private Button _tabMain;
        [SerializeField] private Button _tabAchievement;
        [SerializeField] private Button _tabEvent;
        [SerializeField] private Color _tabActiveColor = new Color(1f, 0.78f, 0.2f, 1f);
        [SerializeField] private Color _tabInactiveColor = new Color(0.3f, 0.6f, 0.3f, 1f);

        [Header("Content")]
        [SerializeField] private Transform _itemContainer;
        [SerializeField] private GameObject _questItemPrefab;

        [Header("Info Bar")]
        [SerializeField] private Text _resetTimerText;
        [SerializeField] private Text _activityText;

        [Header("Activity Bar")]
        [SerializeField] private Slider _activitySlider;
        [SerializeField] private Image[] _chestIcons;
        [SerializeField] private Sprite _chestLocked;
        [SerializeField] private Sprite _chestUnlocked;
        [SerializeField] private Sprite _chestClaimed;

        [Header("Data")]
        [SerializeField] private string _jsonPath = "Data/QuestItems";

        private QuestData _questData;
        private QuestCategory _currentCategory;
        private List<GameObject> _spawnedItems = new List<GameObject>();
        private Dictionary<QuestCategory, Button> _tabButtons = new Dictionary<QuestCategory, Button>();
        private GameObject _torchRoot;
        private MovingClouds _clouds;
        private ParticleSystem _snowParticles;
        private int _snowOriginalSortOrder;

        public void SetReferences(GameObject questPanel, Button closeButton, Button tabDaily, Button tabMain, Button tabAchievement, Button tabEvent, Transform itemContainer, GameObject questItemPrefab, Text resetTimerText, Text activityText, Slider activitySlider, Image[] chestIcons)
        {
            _questPanel = questPanel;
            _closeButton = closeButton;
            _tabDaily = tabDaily;
            _tabMain = tabMain;
            _tabAchievement = tabAchievement;
            _tabEvent = tabEvent;
            _itemContainer = itemContainer;
            _questItemPrefab = questItemPrefab;
            _resetTimerText = resetTimerText;
            _activityText = activityText;
            _activitySlider = activitySlider;
            _chestIcons = chestIcons;
        }

        private void Awake()
        {
            _tabButtons[QuestCategory.Daily] = _tabDaily;
            _tabButtons[QuestCategory.Main] = _tabMain;
            _tabButtons[QuestCategory.Achievement] = _tabAchievement;
            _tabButtons[QuestCategory.Event] = _tabEvent;

            if (_closeButton != null)
                _closeButton.onClick.AddListener(CloseQuest);

            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value != null)
                {
                    var cat = kvp.Key;
                    kvp.Value.onClick.AddListener(() => SwitchTab(cat));
                }
            }

            _torchRoot = GameObject.Find("火把");

            GameObject bgObj = GameObject.Find("背景");
            if (bgObj != null)
            {
                _clouds = bgObj.GetComponent<MovingClouds>();
                _snowParticles = bgObj.GetComponentInChildren<ParticleSystem>();
                if (_snowParticles != null)
                {
                    var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                    if (renderer != null)
                        _snowOriginalSortOrder = renderer.sortingOrder;
                }
            }

            LoadQuestData();
        }

        private void Start()
        {
            if (_questPanel != null)
                _questPanel.SetActive(false);
        }

        private void LoadQuestData()
        {
            var jsonFile = Resources.Load<TextAsset>(_jsonPath);
            if (jsonFile != null)
            {
                _questData = JsonUtility.FromJson<QuestData>(jsonFile.text);
                Debug.Log($"[QuestPanel] Loaded {_questData.items.Length} quests from JSON");
            }
            else
            {
                Debug.LogError($"[QuestPanel] Failed to load JSON: Resources/{_jsonPath}");
                _questData = new QuestData { items = new QuestItemData[0], dailyActivity = 0, dailyActivityMax = 120 };
                return;
            }

            ApplySaveData();
        }

        private void ApplySaveData()
        {
            var save = SaveSystem.Instance;
            if (save == null || save.CurrentSave == null) return;

            var questSave = save.CurrentSave.quests;
            if (questSave == null || questSave.items == null || questSave.items.Count == 0) return;

            // 每日任务重置检查
            string today = System.DateTime.Now.ToString("yyyyMMdd");
            if (questSave.dailyResetDate != today)
            {
                foreach (var item in _questData.items)
                {
                    if (item.category == QuestCategory.Daily)
                    {
                        item.currentCount = 0;
                        item.status = QuestStatus.InProgress;
                    }
                }
                questSave.dailyActivity = 0;
                questSave.dailyResetDate = today;
            }
            else
            {
                _questData.dailyActivity = questSave.dailyActivity;
            }

            // 恢复每个任务的进度
            foreach (var savedItem in questSave.items)
            {
                foreach (var questItem in _questData.items)
                {
                    if (questItem.id == savedItem.id)
                    {
                        questItem.currentCount = savedItem.currentCount;
                        questItem.status = (QuestStatus)savedItem.status;
                        break;
                    }
                }
            }

            Debug.Log($"[QuestPanel] Applied save data to quests");
        }

        private void PersistQuestData()
        {
            var save = SaveSystem.Instance;
            if (save == null || save.CurrentSave == null || _questData == null) return;

            var questSave = save.CurrentSave.quests;
            questSave.items.Clear();
            questSave.dailyActivity = _questData.dailyActivity;
            questSave.dailyResetDate = System.DateTime.Now.ToString("yyyyMMdd");

            foreach (var item in _questData.items)
            {
                questSave.items.Add(new GameSaveData.QuestItemSave
                {
                    id = item.id,
                    currentCount = item.currentCount,
                    status = (int)item.status
                });
            }

            save.SaveGame();
        }

        public void OpenQuest()
        {
            if (_questPanel != null)
                _questPanel.SetActive(true);

            if (_torchRoot != null)
                _torchRoot.SetActive(false);

            if (_clouds != null)
                _clouds.IsPaused = true;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = -10;
                _snowParticles.Pause(true);
            }

            ApplySaveData();
            SwitchTab(QuestCategory.Daily);
        }

        public void CloseQuest()
        {
            if (_questPanel != null)
                _questPanel.SetActive(false);

            if (_torchRoot != null)
                _torchRoot.SetActive(true);

            if (_clouds != null)
                _clouds.IsPaused = false;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = _snowOriginalSortOrder;
                _snowParticles.Play(true);
            }
        }

        private void SwitchTab(QuestCategory category)
        {
            _currentCategory = category;
            UpdateTabVisuals();
            RefreshItemList();
            UpdateInfoBar();
        }

        private void UpdateTabVisuals()
        {
            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value == null) continue;
                var colors = kvp.Value.colors;
                colors.normalColor = kvp.Key == _currentCategory ? _tabActiveColor : _tabInactiveColor;
                colors.selectedColor = colors.normalColor;
                colors.highlightedColor = kvp.Key == _currentCategory ? _tabActiveColor : new Color(0.8f, 0.8f, 0.8f, 1f);
                kvp.Value.colors = colors;
            }
        }

        private void UpdateInfoBar()
        {
            if (_activityText != null && _questData != null)
                _activityText.text = $"⭐ {_questData.dailyActivity}";

            if (_activitySlider != null && _questData != null)
            {
                _activitySlider.maxValue = _questData.dailyActivityMax;
                _activitySlider.value = _questData.dailyActivity;
            }

            UpdateChestIcons();
        }

        private void UpdateChestIcons()
        {
            if (_questData == null || _chestIcons == null) return;
            int[] thresholds = { 30, 60, 90, 120 };
            for (int i = 0; i < _chestIcons.Length && i < thresholds.Length; i++)
            {
                if (_chestIcons[i] == null) continue;
                _chestIcons[i].sprite = _questData.dailyActivity >= thresholds[i] ? _chestUnlocked : _chestLocked;
            }
        }

        private void RefreshItemList()
        {
            foreach (var item in _spawnedItems)
            {
                if (item != null) DestroyImmediate(item);
            }
            _spawnedItems.Clear();

            if (_itemContainer == null || _questItemPrefab == null)
            {
                Debug.LogWarning("[QuestPanel] Item container or prefab is null");
                return;
            }

            foreach (var questData in _questData.items)
            {
                if (questData.category != _currentCategory) continue;

                GameObject itemObj = Instantiate(_questItemPrefab, _itemContainer);
                itemObj.SetActive(true);
                _spawnedItems.Add(itemObj);

                var questItemUI = itemObj.GetComponent<QuestItemUI>();
                if (questItemUI != null)
                    questItemUI.Setup(questData, this);
            }
        }

        public void OnClaimClicked(QuestItemData questData)
        {
            if (questData.status != QuestStatus.Claimable)
            {
                Debug.Log($"[QuestPanel] {questData.name} 不可领取");
                return;
            }

            var wallet = PlayerWallet.Instance;
            if (wallet == null)
            {
                Debug.LogWarning("[QuestPanel] PlayerWallet not found");
                return;
            }

            if (questData.rewards != null)
            {
                foreach (var reward in questData.rewards)
                {
                    switch (reward.rewardType)
                    {
                        case RewardType.Gold: wallet.AddGold(reward.amount); break;
                        case RewardType.Diamond: wallet.AddDiamond(reward.amount); break;
                        case RewardType.Stamina: wallet.AddStamina(reward.amount); break;
                        case RewardType.Exp: PlayerLevelSystem.Instance.AddExp(reward.amount); break;
                    }
                }
            }

            questData.status = QuestStatus.Claimed;
            _questData.dailyActivity += 10;
            Debug.Log($"[QuestPanel] 领取成功: {questData.name}");

            PersistQuestData();
            RefreshItemList();
            UpdateInfoBar();
        }

        public void OnGoToClicked(QuestItemData questData)
        {
            Debug.Log($"[QuestPanel] 前往: {questData.name}");
            CloseQuest();
        }

        public static string GetCategoryName(QuestCategory category)
        {
            return category switch
            {
                QuestCategory.Daily => "每日任务",
                QuestCategory.Main => "主线任务",
                QuestCategory.Achievement => "成就任务",
                QuestCategory.Event => "活动任务",
                _ => "未知"
            };
        }

        public static string GetRewardSymbol(RewardType type)
        {
            return type switch
            {
                RewardType.Gold => "🪙",
                RewardType.Diamond => "💎",
                RewardType.Stamina => "⚡",
                RewardType.Item => "📦",
                RewardType.Exp => "⭐",
                _ => ""
            };
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Data;

namespace TowerDefense.UI
{
    public class AchievementItemUI : MonoBehaviour
    {
        [Header("UI References")]
        [SerializeField] private Image _iconBg;
        [SerializeField] private Text _iconSymbol;
        [SerializeField] private Text _nameText;
        [SerializeField] private Text _descText;
        [SerializeField] private Slider _progressSlider;
        [SerializeField] private Text _progressText;
        [SerializeField] private Text _rewardText;
        [SerializeField] private Button _claimButton;
        [SerializeField] private Text _claimButtonText;
        [SerializeField] private GameObject _completedOverlay;

        private AchievementItemData _data;
        private AchievementPanel _panel;

        public void Setup(AchievementItemData data, AchievementPanel panel)
        {
            _data = data;
            _panel = panel;

            // 图标
            if (_iconBg != null && !string.IsNullOrEmpty(data.iconColorHex))
            {
                Color c;
                if (ColorUtility.TryParseHtmlString(data.iconColorHex, out c))
                    _iconBg.color = c;
            }

            if (_iconSymbol != null)
                _iconSymbol.text = data.iconSymbol ?? "";

            // 文字
            if (_nameText != null)
                _nameText.text = data.name;

            if (_descText != null)
                _descText.text = data.description;

            // 进度条
            if (_progressSlider != null)
            {
                _progressSlider.maxValue = Mathf.Max(data.targetCount, 1);
                _progressSlider.value = Mathf.Min(data.currentCount, data.targetCount);
            }

            if (_progressText != null)
                _progressText.text = $"{Mathf.Min(data.currentCount, data.targetCount)}/{data.targetCount}";

            // 奖励
            if (_rewardText != null)
                _rewardText.text = BuildRewardText(data);

            // 按钮状态
            bool isClaimable = data.status == AchievementStatus.Claimable;
            bool isClaimed = data.status == AchievementStatus.Claimed;

            if (_claimButton != null)
            {
                _claimButton.gameObject.SetActive(isClaimable);
                _claimButton.interactable = isClaimable;
                _claimButton.onClick.RemoveAllListeners();
                if (isClaimable)
                    _claimButton.onClick.AddListener(OnClaimClicked);
            }

            if (_claimButtonText != null)
            {
                if (isClaimable)
                    _claimButtonText.text = "领取";
            }

            // 已完成: 显示奖励+已领取标记
            if (_rewardText != null)
            {
                string rewardStr = BuildRewardText(data);
                if (isClaimed)
                    _rewardText.text = string.IsNullOrEmpty(rewardStr) ? "已领取" : $"{rewardStr} (已领取)";
                else
                    _rewardText.text = rewardStr;
            }

            // 已完成遮罩
            if (_completedOverlay != null)
                _completedOverlay.SetActive(isClaimed);
        }

        private string BuildRewardText(AchievementItemData data)
        {
            if (data.rewards == null || data.rewards.Length == 0) return "";
            var parts = new System.Collections.Generic.List<string>();
            foreach (var r in data.rewards)
            {
                string sym = r.rewardType switch
                {
                    RewardType.Gold => "[金]",
                    RewardType.Diamond => "[钻]",
                    RewardType.Stamina => "[体]",
                    RewardType.Exp => "[经]",
                    _ => ""
                };
                parts.Add($"{sym}x{r.amount}");
            }
            return string.Join("  ", parts);
        }

        private void OnClaimClicked()
        {
            if (_panel != null && _data != null)
                _panel.OnClaimClicked(_data);
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Data;

namespace TowerDefense.UI
{
    public class QuestItemUI : MonoBehaviour
    {
        [Header("UI References")]
        [SerializeField] private Image _iconImage;
        [SerializeField] private Text _nameText;
        [SerializeField] private Text _descText;
        [SerializeField] private Slider _progressSlider;
        [SerializeField] private Text _progressText;
        [SerializeField] private Image _rewardIcon;
        [SerializeField] private Text _rewardText;
        [SerializeField] private Text _expRewardText;
        [SerializeField] private Button _actionButton;
        [SerializeField] private Text _actionText;
        [SerializeField] private GameObject _tagObject;
        [SerializeField] private Text _tagText;

        private QuestItemData _itemData;
        private QuestPanel _questPanel;

        public void SetReferences(Image iconImage, Text nameText, Text descText, Slider progressSlider, Text progressText, Image rewardIcon, Text rewardText, Text expRewardText, Button actionButton, Text actionText, GameObject tagObject, Text tagText)
        {
            _iconImage = iconImage;
            _nameText = nameText;
            _descText = descText;
            _progressSlider = progressSlider;
            _progressText = progressText;
            _rewardIcon = rewardIcon;
            _rewardText = rewardText;
            _expRewardText = expRewardText;
            _actionButton = actionButton;
            _actionText = actionText;
            _tagObject = tagObject;
            _tagText = tagText;
        }

        public void Setup(QuestItemData itemData, QuestPanel questPanel)
        {
            _itemData = itemData;
            _questPanel = questPanel;

            // Name & Description
            if (_nameText != null)
                _nameText.text = itemData.name;

            if (_descText != null)
                _descText.text = itemData.description;

            // Progress
            if (_progressSlider != null)
            {
                _progressSlider.maxValue = itemData.targetCount;
                _progressSlider.value = itemData.currentCount;
            }

            if (_progressText != null)
                _progressText.text = $"{itemData.currentCount}/{itemData.targetCount}";

            // Icon
            if (_iconImage != null)
            {
                if (!string.IsNullOrEmpty(itemData.iconPath))
                {
                    var sprite = Resources.Load<Sprite>(itemData.iconPath);
                    if (sprite != null)
                    {
                        _iconImage.sprite = sprite;
                        _iconImage.color = Color.white;
                    }
                    else
                    {
                        SetCategoryFallbackColor(itemData.category);
                    }
                }
                else
                {
                    SetCategoryFallbackColor(itemData.category);
                }
            }

            // Reward
            int expAmount = 0;
            if (itemData.rewards != null && itemData.rewards.Length > 0)
            {
                var primaryReward = itemData.rewards[0];
                if (_rewardText != null)
                    _rewardText.text = primaryReward.rewardType == RewardType.Exp
                        ? $"⭐x{primaryReward.amount}"
                        : $"{QuestPanel.GetRewardSymbol(primaryReward.rewardType)}x{primaryReward.amount}";

                foreach (var r in itemData.rewards)
                {
                    if (r.rewardType == RewardType.Exp)
                        expAmount += r.amount;
                }
            }

            if (_expRewardText != null)
            {
                _expRewardText.gameObject.SetActive(expAmount > 0);
                if (expAmount > 0)
                    _expRewardText.text = $"⭐+{expAmount}";
            }

            // Tag
            if (_tagObject != null)
            {
                bool hasTag = !string.IsNullOrEmpty(itemData.tag);
                _tagObject.SetActive(hasTag);
                if (hasTag && _tagText != null)
                    _tagText.text = itemData.tag;
            }

            // Action Button
            if (_actionButton != null)
            {
                _actionButton.onClick.RemoveAllListeners();

                if (itemData.status == QuestStatus.Claimed)
                {
                    _actionButton.interactable = false;
                    if (_actionText != null)
                        _actionText.text = "已完成";
                }
                else if (itemData.status == QuestStatus.Claimable)
                {
                    _actionButton.interactable = true;
                    if (_actionText != null)
                        _actionText.text = "领取";

                    var colors = _actionButton.colors;
                    colors.normalColor = new Color(1f, 0.65f, 0.15f, 1f);
                    colors.highlightedColor = new Color(1f, 0.75f, 0.3f, 1f);
                    _actionButton.colors = colors;

                    _actionButton.onClick.AddListener(OnClaimClicked);
                }
                else
                {
                    _actionButton.interactable = true;
                    if (_actionText != null)
                        _actionText.text = "前往";

                    var colors = _actionButton.colors;
                    colors.normalColor = new Color(0.3f, 0.75f, 0.3f, 1f);
                    colors.highlightedColor = new Color(0.4f, 0.85f, 0.4f, 1f);
                    _actionButton.colors = colors;

                    _actionButton.onClick.AddListener(OnGoToClicked);
                }
            }
        }

        private void SetCategoryFallbackColor(QuestCategory category)
        {
            _iconImage.sprite = null;
            _iconImage.color = category switch
            {
                QuestCategory.Daily => new Color(1f, 0.85f, 0.2f, 1f),
                QuestCategory.Main => new Color(0.3f, 0.7f, 1f, 1f),
                QuestCategory.Achievement => new Color(0.8f, 0.5f, 1f, 1f),
                QuestCategory.Event => new Color(1f, 0.4f, 0.4f, 1f),
                _ => Color.white
            };
        }

        private void OnClaimClicked()
        {
            if (_questPanel != null && _itemData != null)
                _questPanel.OnClaimClicked(_itemData);
        }

        private void OnGoToClicked()
        {
            if (_questPanel != null && _itemData != null)
                _questPanel.OnGoToClicked(_itemData);
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using System.Collections;
using TowerDefense.Data;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class ShopItemUI : MonoBehaviour
    {
        [Header("UI References")]
        [SerializeField] private Image _iconImage;
        [SerializeField] private Image _cardBackground;  // 卡片背景
        [SerializeField] private Text _nameText;
        [SerializeField] private Text _descText;
        [SerializeField] private Text _priceText;
        [SerializeField] private Text _originalPriceText;  // 原价（划线价）
        [SerializeField] private Text _tagText;
        [SerializeField] private Text _discountText;
        [SerializeField] private Button _buyButton;
        [SerializeField] private GameObject _tagObject;
        [SerializeField] private GameObject _discountObject;
        [SerializeField] private GameObject _soldOutObject;
        [SerializeField] private GameObject _originalPriceObject;  // 原价区域
        [SerializeField] private CanvasGroup _canvasGroup;  // 用于动画

        // 卡片颜色方案 - 按分类
        private static readonly Color ResourceCardColor = new Color(0.25f, 0.22f, 0.15f, 0.95f);
        private static readonly Color HeroCardColor = new Color(0.15f, 0.18f, 0.28f, 0.95f);
        private static readonly Color TowerCardColor = new Color(0.15f, 0.25f, 0.18f, 0.95f);
        private static readonly Color SpecialCardColor = new Color(0.28f, 0.15f, 0.22f, 0.95f);

        // 标签颜色
        private static readonly Color TagNewColor = new Color(0.2f, 0.8f, 1f, 1f);
        private static readonly Color TagHotColor = new Color(1f, 0.4f, 0.2f, 1f);
        private static readonly Color TagDailyColor = new Color(0.3f, 0.9f, 0.4f, 1f);
        private static readonly Color TagLimitColor = new Color(1f, 0.75f, 0.1f, 1f);

        private ShopItemData _itemData;
        private ShopPanel _shopPanel;

        public void Setup(ShopItemData itemData, ShopPanel shopPanel)
        {
            _itemData = itemData;
            _shopPanel = shopPanel;

            // 卡片背景色
            if (_cardBackground != null)
            {
                _cardBackground.color = itemData.category switch
                {
                    ShopCategory.Resource => ResourceCardColor,
                    ShopCategory.Hero => HeroCardColor,
                    ShopCategory.Tower => TowerCardColor,
                    ShopCategory.Special => SpecialCardColor,
                    _ => new Color(0.2f, 0.2f, 0.2f, 0.9f)
                };
            }

            if (_nameText != null)
                _nameText.text = itemData.name;

            if (_descText != null)
            {
                string rewardText = BuildRewardText(itemData);
                _descText.text = string.IsNullOrEmpty(rewardText) ? itemData.description : rewardText;
            }

            // Price - 折扣时显示划线原价
            if (_priceText != null)
            {
                if (itemData.currencyType == CurrencyType.Free)
                {
                    _priceText.text = "免费";
                    _priceText.color = Color.green;
                }
                else if (itemData.discount > 0)
                {
                    int discountedPrice = itemData.price * (100 - itemData.discount) / 100;
                    string symbol = ShopPanel.GetCurrencySymbol(itemData.currencyType);
                    _priceText.text = $"{symbol}{discountedPrice}";
                    _priceText.color = new Color(1f, 0.85f, 0.2f); // 金色高亮折扣价

                    // 显示原价
                    if (_originalPriceText != null)
                        _originalPriceText.text = $"{itemData.price}";
                    if (_originalPriceObject != null)
                        _originalPriceObject.SetActive(true);
                }
                else
                {
                    string symbol = ShopPanel.GetCurrencySymbol(itemData.currencyType);
                    _priceText.text = $"{symbol}{itemData.price}";
                    _priceText.color = Color.white;
                }
            }

            // 没有折扣时隐藏原价
            if (itemData.discount <= 0 && _originalPriceObject != null)
                _originalPriceObject.SetActive(false);

            // Tag - 带颜色
            if (_tagObject != null)
            {
                bool hasTag = !string.IsNullOrEmpty(itemData.tag);
                _tagObject.SetActive(hasTag);
                if (hasTag && _tagText != null)
                {
                    _tagText.text = itemData.tag;
                    // 标签颜色
                    var tagImage = _tagObject.GetComponent<Image>();
                    if (tagImage != null)
                    {
                        tagImage.color = itemData.tag.ToLower() switch
                        {
                            "new" => TagNewColor,
                            "hot" => TagHotColor,
                            "daily" => TagDailyColor,
                            "限时" => TagLimitColor,
                            _ => TagNewColor
                        };
                    }
                }
            }

            // Discount badge
            if (_discountObject != null)
            {
                bool hasDiscount = itemData.discount > 0;
                _discountObject.SetActive(hasDiscount);
                if (hasDiscount && _discountText != null)
                    _discountText.text = $"-{itemData.discount}%";
            }

            // Icon
            if (_iconImage != null)
            {
                if (!string.IsNullOrEmpty(itemData.iconPath))
                {
                    var sprite = Resources.Load<Sprite>(itemData.iconPath);
                    if (sprite != null)
                    {
                        _iconImage.sprite = sprite;
                        _iconImage.color = Color.white;
                    }
                    else
                    {
                        SetCategoryFallbackColor(itemData.category);
                    }
                }
                else
                {
                    SetCategoryFallbackColor(itemData.category);
                }
            }

            // Sold out check - 更醒目
            bool isSoldOut = itemData.isLimited && itemData.purchasedCount >= itemData.limitCount;
            if (_soldOutObject != null)
                _soldOutObject.SetActive(isSoldOut);

            if (_buyButton != null)
            {
                _buyButton.interactable = !isSoldOut;

                // 售罄时按钮变灰
                var buyImage = _buyButton.GetComponent<Image>();
                if (buyImage != null)
                {
                    buyImage.color = isSoldOut
                        ? new Color(0.3f, 0.3f, 0.3f, 1f)
                        : new Color(0.2f, 0.75f, 0.3f, 1f);  // 绿色可购买
                }

                _buyButton.onClick.RemoveAllListeners();
                _buyButton.onClick.AddListener(OnBuyClicked);
            }

            // 限购信息 - 在描述后追加
            if (_descText != null && itemData.isLimited && itemData.limitCount > 0)
            {
                int remaining = itemData.limitCount - itemData.purchasedCount;
                _descText.text += $"\n<color=#FFD700>限购{itemData.limitCount}次 (剩余{remaining}次)</color>";
            }
        }

        private void SetCategoryFallbackColor(ShopCategory category)
        {
            _iconImage.sprite = null;
            _iconImage.color = category switch
            {
                ShopCategory.Resource => new Color(1f, 0.85f, 0.2f, 1f),
                ShopCategory.Hero => new Color(0.3f, 0.7f, 1f, 1f),
                ShopCategory.Tower => new Color(0.4f, 1f, 0.4f, 1f),
                ShopCategory.Special => new Color(1f, 0.4f, 0.8f, 1f),
                _ => Color.white
            };
        }

        public static string BuildRewardText(ShopItemData data)
        {
            var parts = new System.Collections.Generic.List<string>();
            if (data.rewardGold > 0) parts.Add($"🪙×{data.rewardGold}");
            if (data.rewardDiamond > 0) parts.Add($"💎×{data.rewardDiamond}");
            if (data.rewardStamina > 0) parts.Add($"⚡×{data.rewardStamina}");
            return string.Join("  ", parts);
        }

        private void OnBuyClicked()
        {
            if (_shopPanel != null && _itemData != null)
            {
                _shopPanel.OnBuyClicked(_itemData);
            }
        }
    }
}

