using UnityEngine;

namespace TowerDefense.UI
{
    public class FlickeringTorch : MonoBehaviour
    {
        [Header("Flame Settings")]
        [SerializeField] private float _minLightIntensity = 1.2f;
        [SerializeField] private float _maxLightIntensity = 2.0f;
        [SerializeField] private float _flickerSpeed = 5f;
        [SerializeField] private Color _flameColor = new Color(1f, 0.6f, 0.1f, 1f);
        [SerializeField] private Color _flameTipColor = new Color(1f, 0.9f, 0.3f, 1f);

        private Light _pointLight;
        private ParticleSystem _flameParticles;
        private float _randomOffset;

        private void Start()
        {
            _randomOffset = Random.Range(0f, 100f);
            SetupPole();
            SetupBowl();
            SetupFlame();
            SetupLight();
        }

        private void SetupPole()
        {
            GameObject pole = GameObject.CreatePrimitive(PrimitiveType.Cylinder);
            pole.name = "Pole";
            pole.transform.SetParent(transform, false);
            pole.transform.localPosition = new Vector3(0, -0.5f, 0);
            pole.transform.localScale = new Vector3(0.08f, 0.5f, 0.08f);

            Destroy(pole.GetComponent<Collider>());
            Renderer rend = pole.GetComponent<Renderer>();
            rend.material = new Material(Shader.Find("Standard"));
            rend.material.color = new Color(0.5f, 0.45f, 0.4f);
            rend.material.SetFloat("_Glossiness", 0.1f);
        }

        private void SetupBowl()
        {
            GameObject bowl = GameObject.CreatePrimitive(PrimitiveType.Cylinder);
            bowl.name = "Bowl";
            bowl.transform.SetParent(transform, false);
            bowl.transform.localPosition = new Vector3(0, 0.05f, 0);
            bowl.transform.localScale = new Vector3(0.15f, 0.04f, 0.15f);

            Destroy(bowl.GetComponent<Collider>());
            Renderer rend = bowl.GetComponent<Renderer>();
            rend.material = new Material(Shader.Find("Standard"));
            rend.material.color = new Color(0.4f, 0.35f, 0.3f);
            rend.material.SetFloat("_Glossiness", 0.2f);
        }

        private void SetupFlame()
        {
            GameObject flameObj = new GameObject("Flame");
            flameObj.transform.SetParent(transform, false);
            flameObj.transform.localPosition = new Vector3(0, 0.15f, 0);

            _flameParticles = flameObj.AddComponent<ParticleSystem>();

            // Stop before modifying duration to avoid assert
            _flameParticles.Stop(true, ParticleSystemStopBehavior.StopEmittingAndClear);

            var main = _flameParticles.main;
            main.duration = 2f;
            main.loop = true;
            main.startLifetime = new ParticleSystem.MinMaxCurve(0.4f, 0.8f);
            main.startSpeed = new ParticleSystem.MinMaxCurve(0.3f, 0.8f);
            main.startSize = new ParticleSystem.MinMaxCurve(0.08f, 0.25f);
            main.startColor = new ParticleSystem.MinMaxGradient(_flameColor, _flameTipColor);
            main.gravityModifier = new ParticleSystem.MinMaxCurve(-0.3f, -0.6f);
            main.simulationSpace = ParticleSystemSimulationSpace.Local;
            main.maxParticles = 50;
            main.startRotation = new ParticleSystem.MinMaxCurve(0f, Mathf.PI * 2f);

            var shape = _flameParticles.shape;
            shape.shapeType = ParticleSystemShapeType.Cone;
            shape.angle = 15f;
            shape.radius = 0.03f;
            shape.length = 0.1f;

            var colorOverLifetime = _flameParticles.colorOverLifetime;
            colorOverLifetime.enabled = true;
            Gradient grad = new Gradient();
            grad.SetKeys(
                new GradientColorKey[] {
                    new GradientColorKey(_flameColor, 0f),
                    new GradientColorKey(_flameTipColor, 0.5f),
                    new GradientColorKey(new Color(1f, 0.3f, 0f), 1f)
                },
                new GradientAlphaKey[] {
                    new GradientAlphaKey(0.9f, 0f),
                    new GradientAlphaKey(0.7f, 0.5f),
                    new GradientAlphaKey(0f, 1f)
                }
            );
            colorOverLifetime.color = new ParticleSystem.MinMaxGradient(grad);

            var sizeOverLifetime = _flameParticles.sizeOverLifetime;
            sizeOverLifetime.enabled = true;
            AnimationCurve sizeCurve = new AnimationCurve();
            sizeCurve.AddKey(0f, 1f);
            sizeCurve.AddKey(0.3f, 0.9f);
            sizeCurve.AddKey(1f, 0.1f);
            sizeOverLifetime.size = new ParticleSystem.MinMaxCurve(1f, sizeCurve);

            var velocityOverLifetime = _flameParticles.velocityOverLifetime;
            velocityOverLifetime.enabled = true;
            velocityOverLifetime.x = new ParticleSystem.MinMaxCurve(-0.2f, 0.2f);
            velocityOverLifetime.y = new ParticleSystem.MinMaxCurve(0.5f, 1.2f);
            velocityOverLifetime.z = new ParticleSystem.MinMaxCurve(-0.2f, 0.2f);

            var emission = _flameParticles.emission;
            emission.rateOverTime = new ParticleSystem.MinMaxCurve(25f, 40f);

            var renderer = _flameParticles.GetComponent<ParticleSystemRenderer>();
            renderer.renderMode = ParticleSystemRenderMode.Billboard;
            renderer.material = new Material(Shader.Find("Particles/Standard Unlit"));
            renderer.material.SetFloat("_Mode", 1);
            renderer.material.color = _flameColor;
            renderer.trailMaterial = null;

            _flameParticles.Play();
        }

        private void SetupLight()
        {
            GameObject lightObj = new GameObject("TorchLight");
            lightObj.transform.SetParent(transform, false);
            lightObj.transform.localPosition = new Vector3(0, 0.25f, 0);

            _pointLight = lightObj.AddComponent<Light>();
            _pointLight.type = LightType.Point;
            _pointLight.intensity = 1.5f;
            _pointLight.range = 6f;
            _pointLight.color = new Color(1f, 0.7f, 0.3f);
            _pointLight.shadows = LightShadows.Soft;
            _pointLight.shadowStrength = 0.5f;
        }

        private void Update()
        {
            if (_pointLight == null) return;

            float noise = Mathf.PerlinNoise(Time.time * _flickerSpeed, _randomOffset);
            _pointLight.intensity = Mathf.Lerp(_minLightIntensity, _maxLightIntensity, noise);

            float sizeNoise = Mathf.PerlinNoise(Time.time * 3f, _randomOffset + 50f);
            if (_flameParticles != null)
            {
                var main = _flameParticles.main;
                main.startSize = new ParticleSystem.MinMaxCurve(0.04f + sizeNoise * 0.02f, 0.12f + sizeNoise * 0.06f);
            }
        }
    }
}

using UnityEngine;
using UnityEngine.UI;

namespace TowerDefense.UI
{
    public class MovingClouds : MonoBehaviour
    {
        [Header("Cloud Settings")]
        [SerializeField] private int _cloudCount = 8;
        [SerializeField] private float _minSpeed = 25f;
        [SerializeField] private float _maxSpeed = 60f;
        [SerializeField] private float _minScale = 0.5f;
        [SerializeField] private float _maxScale = 1.6f;
        [SerializeField] private float _cloudAlpha = 0.55f;

        [Header("Spawn Range (UI coordinates)")]
        [SerializeField] private float _spawnY = 250f;
        [SerializeField] private float _yRandomRange = 350f;
        [SerializeField] private int _cloudSortOrder = -5;

        public bool IsPaused { get; set; }

        private RectTransform _canvasRect;
        private float _canvasWidth;
        private float _canvasHeight;

        private void Start()
        {
            Canvas canvas = GetComponentInParent<Canvas>();
            if (canvas != null)
            {
                _canvasRect = canvas.GetComponent<RectTransform>();
                _canvasWidth = _canvasRect.rect.width;
                _canvasHeight = _canvasRect.rect.height;
            }
            else
            {
                _canvasWidth = 1920f;
                _canvasHeight = 1080f;
            }

            for (int i = 0; i < _cloudCount; i++)
            {
                CreateCloud(randomX: true);
            }
        }

        private void CreateCloud(bool randomX = false)
        {
            GameObject cloudObj = new GameObject("Cloud");
            cloudObj.transform.SetParent(transform, false);

            RectTransform rt = cloudObj.AddComponent<RectTransform>();

            Canvas cloudCanvas = cloudObj.AddComponent<Canvas>();
            cloudCanvas.overrideSorting = true;
            cloudCanvas.sortingOrder = _cloudSortOrder;

            Image cloudImg = cloudObj.AddComponent<Image>();

            Texture2D tex = GenerateCloudTexture();
            Sprite sprite = Sprite.Create(tex, new Rect(0, 0, tex.width, tex.height), new Vector2(0.5f, 0.5f));
            cloudImg.sprite = sprite;
            cloudImg.color = new Color(1f, 1f, 1f, _cloudAlpha);
            cloudImg.raycastTarget = false;

            float scale = Random.Range(_minScale, _maxScale);
            rt.localScale = new Vector3(scale, scale, 1f);

            float startX = randomX ? Random.Range(-_canvasWidth / 2, _canvasWidth / 2) : _canvasWidth / 2 + 200f;
            float startY = _spawnY + Random.Range(-_yRandomRange, _yRandomRange);
            rt.anchoredPosition = new Vector2(startX, startY);

            CloudMover mover = cloudObj.AddComponent<CloudMover>();
            float speed = Random.Range(_minSpeed, _maxSpeed);
            mover.Initialize(speed, _canvasWidth, rt, this);
        }

        private Texture2D GenerateCloudTexture()
        {
            int w = 256;
            int h = 128;
            Texture2D tex = new Texture2D(w, h);
            Color[] pixels = new Color[w * h];

            for (int y = 0; y < h; y++)
            {
                for (int x = 0; x < w; x++)
                {
                    float nx = (float)x / w;
                    float ny = (float)y / h;

                    float d = Ellipse(nx, ny, 0.5f, 0.45f, 0.4f, 0.35f);
                    d = Mathf.Max(d, Ellipse(nx, ny, 0.3f, 0.55f, 0.22f, 0.25f));
                    d = Mathf.Max(d, Ellipse(nx, ny, 0.7f, 0.55f, 0.22f, 0.25f));
                    d = Mathf.Max(d, Ellipse(nx, ny, 0.5f, 0.6f, 0.28f, 0.2f));
                    d = Mathf.Max(d, Ellipse(nx, ny, 0.4f, 0.7f, 0.15f, 0.12f));
                    d = Mathf.Max(d, Ellipse(nx, ny, 0.6f, 0.7f, 0.15f, 0.12f));

                    float alpha = Mathf.SmoothStep(0f, 1f, d);
                    pixels[y * w + x] = new Color(1f, 1f, 1f, alpha);
                }
            }

            tex.SetPixels(pixels);
            tex.Apply();
            return tex;
        }

        private float Ellipse(float nx, float ny, float cx, float cy, float rx, float ry)
        {
            float dx = (nx - cx) / rx;
            float dy = (ny - cy) / ry;
            return 1f - (dx * dx + dy * dy);
        }

        internal void OnCloudExitedScreen(CloudMover mover)
        {
            CreateCloud(randomX: false);
            Destroy(mover.gameObject);
        }

        internal class CloudMover : MonoBehaviour
        {
            private float _speed;
            private float _canvasWidth;
            private RectTransform _rt;
            private MovingClouds _owner;

            public void Initialize(float speed, float canvasWidth, RectTransform rt, MovingClouds owner)
            {
                _speed = speed;
                _canvasWidth = canvasWidth;
                _rt = rt;
                _owner = owner;
            }

            private void Update()
            {
                if (_rt == null || _owner.IsPaused) return;

                Vector2 pos = _rt.anchoredPosition;
                pos.x -= _speed * Time.deltaTime;
                _rt.anchoredPosition = pos;

                if (pos.x < -_canvasWidth / 2 - 300f)
                {
                    _owner.OnCloudExitedScreen(this);
                }
            }
        }
    }
}

using UnityEngine;
using UnityEngine.UI;

namespace TowerDefense.UI
{
    public class UIPatrolEnemy : MonoBehaviour
    {
        [Header("Patrol Settings")]
        [SerializeField] private float _moveSpeed = 80f;
        [SerializeField] private float _patrolMinX = -700f;
        [SerializeField] private float _patrolMaxX = 700f;
        [SerializeField] private float _patrolY = -200f;
        [SerializeField] private float _idleChance = 0.3f;
        [SerializeField] private float _idleDurationMin = 1.5f;
        [SerializeField] private float _idleDurationMax = 4f;
        [SerializeField] private float _bobSpeed = 2f;
        [SerializeField] private float _bobAmount = 8f;

        [Header("Sprite")]
        [SerializeField] private Sprite _enemySprite;

        private RectTransform _rt;
        private Image _img;
        private int _direction = 1;
        private bool _isIdle;
        private float _idleTimer;
        private float _baseY;
        private float _randomOffset;

        private void Start()
        {
            _rt = GetComponent<RectTransform>();
            _img = GetComponent<Image>();
            _baseY = _patrolY + Random.Range(-50f, 50f);
            _randomOffset = Random.Range(0f, 100f);

            if (_enemySprite != null)
            {
                _img.sprite = _enemySprite;
                _img.SetNativeSize();
            }
            _img.raycastTarget = false;

            float startX = Random.Range(_patrolMinX, _patrolMaxX);
            _rt.anchoredPosition = new Vector2(startX, _baseY);

            _direction = Random.value > 0.5f ? 1 : -1;
            UpdateFlip();
        }

        private void Update()
        {
            if (_rt == null) return;

            if (_isIdle)
            {
                _idleTimer -= Time.deltaTime;
                if (_idleTimer <= 0f)
                {
                    _isIdle = false;
                    _direction = Random.value > 0.5f ? 1 : -1;
                    UpdateFlip();
                }
            }
            else
            {
                float moveAmount = _moveSpeed * Time.deltaTime * _direction;
                Vector2 pos = _rt.anchoredPosition;
                pos.x += moveAmount;

                if (pos.x > _patrolMaxX)
                {
                    pos.x = _patrolMaxX;
                    StartIdleOrTurn();
                }
                else if (pos.x < _patrolMinX)
                {
                    pos.x = _patrolMinX;
                    StartIdleOrTurn();
                }

                _rt.anchoredPosition = pos;
            }

            float bobOffset = Mathf.Sin((Time.time + _randomOffset) * _bobSpeed) * _bobAmount;
            Vector2 currentPos = _rt.anchoredPosition;
            currentPos.y = _baseY + bobOffset;
            _rt.anchoredPosition = currentPos;
        }

        private void StartIdleOrTurn()
        {
            if (Random.value < _idleChance)
            {
                _isIdle = true;
                _idleTimer = Random.Range(_idleDurationMin, _idleDurationMax);
            }
            else
            {
                _direction *= -1;
                UpdateFlip();
            }
        }

        private void UpdateFlip()
        {
            if (_img == null) return;
            Vector3 scale = _img.transform.localScale;
            scale.x = Mathf.Abs(scale.x) * _direction;
            _img.transform.localScale = scale;
        }
    }
}

