using UnityEngine;

namespace TowerDefense.Core
{
    /// <summary>
    /// 模块模式检测器，提供全局静态标志来判断塔防是否以模块模式运行。
    /// 由 TowerDefenseGameModule 在激活时设置。
    /// </summary>
    public static class ModuleModeDetector
    {
        /// <summary>
        /// 塔防是否以模块模式运行（通过家园传送门进入，而非独立启动）。
        /// </summary>
        public static bool IsModuleMode { get; set; } = false;

        /// <summary>
        /// 检测当前是否在模块模式场景中运行。
        /// </summary>
        public static bool DetectFromScene()
        {
            string sceneName = UnityEngine.SceneManagement.SceneManager.GetActiveScene().name;
            return sceneName == "TDGameScene";
        }
    }
}

using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Save;

namespace TowerDefense.Module
{
    /// <summary>
    /// 塔防游戏模块，继承共享 GameModule 基类。
    /// 作为塔防玩法在 HomeBase 架构中的入口。
    /// </summary>
    public class TowerDefenseGameModule : GameModule
    {
        [Header("模块配置")]
        [SerializeField] private string _moduleIdInternal = "towerdefense";
        [SerializeField] private string _displayNameInternal = "塔防";
        [SerializeField] private string _sceneNameInternal = "TDGameScene";

        /// <summary>当前模块实例</summary>
        public static TowerDefenseGameModule Instance { get; private set; }

        private void Reset()
        {
            _moduleId = _moduleIdInternal;
            _displayName = _displayNameInternal;
            _sceneName = _sceneNameInternal;
        }

        private void Awake()
        {
            if (string.IsNullOrEmpty(_moduleId)) _moduleId = _moduleIdInternal;
            if (string.IsNullOrEmpty(_displayName)) _displayName = _displayNameInternal;
            if (string.IsNullOrEmpty(_sceneName)) _sceneName = _sceneNameInternal;

            Instance = this;
        }

        public override void Activate()
        {
            // 设置全局模块模式标志
            Core.ModuleModeDetector.IsModuleMode = true;

            base.Activate();

            // 注册到模块管理器
            ModuleManager.Instance.RegisterModule(this);

            Debug.Log("[TowerDefenseGameModule] 塔防模块已激活（模块模式）");
        }

        public override void Deactivate()
        {
            CleanupTowerDefenseState();

            // 清除全局模块模式标志
            Core.ModuleModeDetector.IsModuleMode = false;

            Instance = null;
            base.Deactivate();

            Debug.Log("[TowerDefenseGameModule] 塔防模块已停用");
        }

        /// <summary>
        /// 清理塔防运行状态，确保回到家园时无残留。
        /// </summary>
        private void CleanupTowerDefenseState()
        {
            // 重置时间缩放
            Time.timeScale = 1f;

            // 清理塔防 EventBus
            Core.EventBus.Clear();

            // 停止所有协程
            StopAllCoroutines();
        }

        #region 存档

        public override string GetModuleSaveData()
        {
            var adapter = new TDSaveAdapter();
            return adapter.CollectSaveData();
        }

        public override void RestoreModuleSaveData(string jsonData)
        {
            var adapter = new TDSaveAdapter();
            adapter.RestoreSaveData(jsonData);
        }

        #endregion
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Core;

namespace TowerDefense.Module
{
    /// <summary>
    /// 塔防返回家园按钮，仅在模块模式下显示。
    /// 挂载在 TDGameScene 的 Canvas 中。
    /// </summary>
    public class TDReturnButton : MonoBehaviour
    {
        [Header("UI")]
        [SerializeField] private Button _returnButton;
        [SerializeField] private GameObject _returnButtonObject;

        [Header("场景桥接")]
        [SerializeField] private TDSceneBridge _sceneBridge;

        private void Start()
        {
            // 仅在模块模式下显示返回按钮
            bool isModuleMode = ModuleModeDetector.IsModuleMode;

            if (_returnButtonObject != null)
            {
                _returnButtonObject.SetActive(isModuleMode);
            }

            if (_returnButton != null && isModuleMode)
            {
                _returnButton.onClick.AddListener(OnReturnClicked);
            }
        }

        private void OnDestroy()
        {
            if (_returnButton != null)
            {
                _returnButton.onClick.RemoveListener(OnReturnClicked);
            }
        }

        private void OnReturnClicked()
        {
            if (_sceneBridge != null)
            {
                _sceneBridge.ReturnToHome();
            }
            else
            {
                Sttop5.Shared.Core.ModuleManager.Instance.DeactivateCurrentModule();
            }
        }
    }
}

