using UnityEngine;
using Sttop5.Shared.Core;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 传送门建筑，点击后进入指定的小游戏模块。
    /// </summary>
    public class PortalBuilding : BuildingBase
    {
        [Header("传送门特效")]
        [SerializeField] private Color _portalColor = new Color(0.3f, 0.5f, 1f, 0.8f);
        [SerializeField] private float _pulseSpeed = 2f;
        [SerializeField] private float _pulseAmount = 0.1f;

        private SpriteRenderer _renderer;
        private float _timer;
        private bool _isHovered = false;
        private Vector3 _baseScale;

        public string TargetModuleId => _data != null ? _data.targetModuleId : "";
        public string TargetSceneName => _data != null ? _data.targetSceneName : "";

        protected override void OnUpgraded()
        {
            // 传送门升级可以减少体力消耗等
        }

        private void Start()
        {
            _renderer = GetComponent<SpriteRenderer>();
            _baseScale = transform.localScale;
            if (_renderer != null)
            {
                _renderer.color = _portalColor;
            }
        }

        private new void Update()
        {
            _timer += Time.deltaTime;

            // 脉冲动画（在原始缩放基础上微调）
            if (_renderer != null)
            {
                float pulse = 1f + Mathf.Sin(_timer * _pulseSpeed) * _pulseAmount;
                transform.localScale = _baseScale * pulse;
            }
        }

        /// <summary>
        /// 点击传送门时调用，进入小游戏。
        /// </summary>
        public void OnPortalClicked()
        {
            if (string.IsNullOrEmpty(TargetModuleId))
            {
                Debug.LogWarning("[PortalBuilding] 未配置目标模块");
                return;
            }

            var moduleManager = ModuleManager.Instance;
            if (moduleManager == null)
            {
                Debug.LogError("[PortalBuilding] ModuleManager 未找到");
                return;
            }

            // 检查模块是否已注册
            var module = moduleManager.GetModule(TargetModuleId);
            if (module == null)
            {
                Debug.LogWarning($"[PortalBuilding] 模块未注册: {TargetModuleId}");
                return;
            }

            Debug.Log($"[PortalBuilding] 进入传送门: {_data.buildingName} → {TargetModuleId}");
            moduleManager.ActivateModule(TargetModuleId);
        }

        private void OnMouseDown()
        {
            if (!_isPlaced) return;
            OnPortalClicked();
        }

        private void OnMouseEnter()
        {
            _isHovered = true;
            if (_renderer != null)
                _renderer.color = new Color(_portalColor.r, _portalColor.g, _portalColor.b, 1f);
        }

        private void OnMouseExit()
        {
            _isHovered = false;
            if (_renderer != null)
                _renderer.color = _portalColor;
        }
    }
}

using System;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Save;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 家园主控制器，管理家园场景的初始化和生命周期。
    /// 作为 GameModule 注册到 ModuleManager。
    /// </summary>
    public class HomeManager : GameModule
    {
        private const string MODULE_ID = "home";
        private const string MODULE_DISPLAY_NAME = "家园";
        private const string SAVE_KEY = "homebase";

        [Header("组件引用")]
        [SerializeField] private BuildingManager _buildingManager;
        [SerializeField] private ResourceManager _resourceManager;

        [Header("初始建筑")]
        [SerializeField] private BuildingData[] _starterBuildings;
        [SerializeField] private Vector3[] _starterPositions;

        private bool _isLoaded = false;

        private void Awake()
        {
            _moduleId = MODULE_ID;
            _displayName = MODULE_DISPLAY_NAME;
            _sceneName = gameObject.scene.name;
        }

        private void Start()
        {
            InitializeHome();
        }

        private void InitializeHome()
        {
            if (_isLoaded) return;

            // 注册到 ModuleManager
            var moduleManager = ModuleManager.Instance;
            if (moduleManager != null)
            {
                moduleManager.RegisterModule(this);
            }

            // 尝试从存档加载
            LoadHomeSave();

            // 如果没有建筑，放置初始建筑
            if (_buildingManager.Buildings.Count == 0)
            {
                PlaceStarterBuildings();
            }

            _isLoaded = true;
            Debug.Log("[HomeManager] 家园初始化完成");
        }

        private void PlaceStarterBuildings()
        {
            if (_starterBuildings == null || _starterPositions == null) return;

            int count = Mathf.Min(_starterBuildings.Length, _starterPositions.Length);
            for (int i = 0; i < count; i++)
            {
                if (_starterBuildings[i] != null)
                {
                    _buildingManager.PlaceBuilding(_starterBuildings[i], _starterPositions[i]);
                }
            }

            Debug.Log($"[HomeManager] 放置 {count} 个初始建筑");
        }

        #region 存档

        public override string GetModuleSaveData()
        {
            var saveData = new HomeSaveData();
            _resourceManager?.SaveToSave(saveData);
            saveData.buildings = _buildingManager?.ExportSaveData();
            return JsonUtility.ToJson(saveData);
        }

        public override void RestoreModuleSaveData(string jsonData)
        {
            if (string.IsNullOrEmpty(jsonData)) return;

            try
            {
                var saveData = JsonUtility.FromJson<HomeSaveData>(jsonData);
                _resourceManager?.LoadFromSave(saveData);
                _buildingManager?.RestoreFromSaveData(saveData.buildings);
            }
            catch (Exception e)
            {
                Debug.LogError($"[HomeManager] 恢复存档失败: {e.Message}");
            }
        }

        private void LoadHomeSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null) return;

            string json = saveSystem.LoadModuleData(SAVE_KEY);
            if (!string.IsNullOrEmpty(json))
            {
                RestoreModuleSaveData(json);
                Debug.Log("[HomeManager] 家园存档已加载");
            }
        }

        private void SaveHomeData()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null) return;

            string json = GetModuleSaveData();
            saveSystem.SaveModuleData(SAVE_KEY, json, 1);
        }

        #endregion

        #region 模块生命周期

        public override void Activate()
        {
            base.Activate();
            Debug.Log("[HomeManager] 家园已激活");
        }

        public override void Deactivate()
        {
            SaveHomeData();
            base.Deactivate();
            Debug.Log("[HomeManager] 家园已停用");
        }

        #endregion

        #region 按钮回调

        /// <summary>
        /// 收集所有资源按钮回调。
        /// </summary>
        public void OnCollectAllClicked()
        {
            _resourceManager?.CollectAllResources();
        }

        #endregion

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) SaveHomeData();
        }

        private void OnApplicationQuit()
        {
            SaveHomeData();
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;

namespace Sttop5.Shared.Core
{
    /// <summary>
    /// 模块管理器，负责注册、激活、停用游戏模块。
    /// 管理从家园进入小游戏的完整生命周期。
    /// </summary>
    public class ModuleManager : Singleton<ModuleManager>
    {
        private readonly Dictionary<string, GameModule> _modules = new Dictionary<string, GameModule>();
        private GameModule _activeModule;

        /// <summary>当前激活的模块</summary>
        public GameModule ActiveModule => _activeModule;

        /// <summary>当前激活的模块ID，无模块时为 "home"</summary>
        public string ActiveModuleId => _activeModule != null ? _activeModule.ModuleId : "home";

        /// <summary>模块切换开始回调</summary>
        public event Action<string, string> OnModuleSwitching;

        /// <summary>模块切换完成回调</summary>
        public event Action<string> OnModuleSwitched;

        /// <summary>
        /// 注册一个游戏模块。
        /// </summary>
        public void RegisterModule(GameModule module)
        {
            if (module == null || string.IsNullOrEmpty(module.ModuleId))
            {
                Debug.LogError("[ModuleManager] 无法注册空模块或无ID的模块");
                return;
            }

            if (_modules.ContainsKey(module.ModuleId))
            {
                Debug.LogWarning($"[ModuleManager] 模块已注册，将被替换: {module.ModuleId}");
            }

            _modules[module.ModuleId] = module;
            Debug.Log($"[ModuleManager] 模块已注册: {module.DisplayName} ({module.ModuleId})");
        }

        /// <summary>
        /// 注销一个游戏模块。
        /// </summary>
        public void UnregisterModule(string moduleId)
        {
            if (_modules.ContainsKey(moduleId))
            {
                if (_activeModule != null && _activeModule.ModuleId == moduleId)
                {
                    DeactivateCurrentModule();
                }
                _modules.Remove(moduleId);
                Debug.Log($"[ModuleManager] 模块已注销: {moduleId}");
            }
        }

        /// <summary>
        /// 激活指定模块，通过场景加载。
        /// </summary>
        public void ActivateModule(string moduleId)
        {
            if (!_modules.TryGetValue(moduleId, out GameModule module))
            {
                Debug.LogError($"[ModuleManager] 未找到模块: {moduleId}");
                return;
            }

            if (_activeModule != null && _activeModule.ModuleId == moduleId)
            {
                Debug.LogWarning($"[ModuleManager] 模块已激活: {moduleId}");
                return;
            }

            string fromModule = ActiveModuleId;
            OnModuleSwitching?.Invoke(fromModule, moduleId);

            // 停用当前模块
            if (_activeModule != null)
            {
                _activeModule.Deactivate();
            }

            // 加载模块场景
            if (!string.IsNullOrEmpty(module.SceneName))
            {
                SceneLoader.Instance.LoadSceneAdditive(module.SceneName, () =>
                {
                    module.Activate();
                    _activeModule = module;
                    OnModuleSwitched?.Invoke(moduleId);

                    GlobalEventBus.Publish(new ModuleSwitchEvent
                    {
                        FromModule = fromModule,
                        ToModule = moduleId
                    });
                });
            }
            else
            {
                module.Activate();
                _activeModule = module;
                OnModuleSwitched?.Invoke(moduleId);
            }
        }

        /// <summary>
        /// 停用当前模块并返回家园。
        /// </summary>
        public void DeactivateCurrentModule()
        {
            if (_activeModule == null)
            {
                Debug.LogWarning("[ModuleManager] 当前无激活模块");
                return;
            }

            string moduleId = _activeModule.ModuleId;
            string sceneName = _activeModule.SceneName;

            _activeModule.Deactivate();

            if (!string.IsNullOrEmpty(sceneName))
            {
                SceneLoader.Instance.UnloadScene(sceneName);
            }

            _activeModule = null;
            Debug.Log($"[ModuleManager] 模块已停用，返回家园: {moduleId}");
        }

        /// <summary>
        /// 获取已注册的模块。
        /// </summary>
        public GameModule GetModule(string moduleId)
        {
            _modules.TryGetValue(moduleId, out GameModule module);
            return module;
        }

        /// <summary>
        /// 获取所有已注册模块。
        /// </summary>
        public IReadOnlyDictionary<string, GameModule> GetAllModules()
        {
            return _modules;
        }

        /// <summary>
        /// 保存所有模块的存档数据。
        /// </summary>
        public Dictionary<string, string> CollectAllModuleSaveData()
        {
            var result = new Dictionary<string, string>();
            foreach (var kvp in _modules)
            {
                try
                {
                    string data = kvp.Value.GetModuleSaveData();
                    if (!string.IsNullOrEmpty(data))
                    {
                        result[kvp.Key] = data;
                    }
                }
                catch (Exception e)
                {
                    Debug.LogError($"[ModuleManager] 获取模块存档失败: {kvp.Key} - {e.Message}");
                }
            }
            return result;
        }
    }
}

