    // Save as new scene
    var newScene = EditorSceneManager.NewScene(NewSceneSetup.EmptyScene, NewSceneMode.Additive);

    // Copy all root objects
    var rootObjects = sourceScene.GetRootGameObjects();
    foreach (var obj in rootObjects)
    {
        // We can't directly move objects between scenes easily, so let's use a different approach
    }

    // Close the source scene without saving
    EditorSceneManager.CloseScene(sourceScene, false);

    // Use AssetDatabase to copy the file instead
    System.IO.File.Copy(sourcePath, destPath);
    AssetDatabase.ImportAsset(destPath);
    Debug.Log($"TDGameScene created at {destPath}");
}

