var scene = EditorSceneManager.OpenScene("Assets/_Modules/TowerDefense/Scenes/TDGameScene.scene", OpenSceneMode.Additive);
Debug.Log($"Opened scene: {scene.name}, root count: {scene.rootCount}");

// List root objects
for (int i = 0; i < scene.rootCount; i++)
{
    var obj = scene.GetRootGameObjects()[i];
    Debug.Log($"  Root: {obj.name}");
}

// Create TowerDefenseGameModule object
var moduleObj = new GameObject("[TowerDefenseModule]");
SceneManager.MoveGameObjectToScene(moduleObj, scene);
moduleObj.AddComponent<TowerDefense.Module.TowerDefenseGameModule>();

// Create TDSceneBridge object
var bridgeObj = new GameObject("[TDSceneBridge]");
SceneManager.MoveGameObjectToScene(bridgeObj, scene);
bridgeObj.AddComponent<TowerDefense.Module.TDSceneBridge>();

Debug.Log("Added TowerDefenseGameModule and TDSceneBridge to TDGameScene");

// Save the scene
EditorSceneManager.SaveScene(scene);
Debug.Log("TDGameScene saved");

// Close the scene
EditorSceneManager.CloseScene(scene, false);
Debug.Log("TDGameScene closed");

