args.script:
using UnityEditor;
using UnityEditor.SceneManagement;
using UnityEngine;
using UnityEngine.SceneManagement;
using UnityEngine.UI;

// Open TDGameScene additively
var scene = EditorSceneManager.OpenScene("Assets/_Modules/TowerDefense/Scenes/TDGameScene.scene", OpenSceneMode.Additive);
Debug.Log($"Opened scene: {scene.name}");

// Find the Canvas
var canvas = scene.GetRootGameObjects().FirstOrDefault(o => o.name == "画布");
if (canvas == null)
{
    Debug.LogError("Canvas not found");
}
else
{
    Debug.Log($"Found Canvas: {canvas.name}");

    // Find existing UI elements for reference
    foreach (Transform child in canvas.transform)
    {
        Debug.Log($"  Canvas child: {child.name}");
    }

    // Create a return button in the top-left corner
    var returnBtnObj = new GameObject("ReturnHomeButton");
    returnBtnObj.transform.SetParent(canvas.transform, false);

    var rectTransform = returnBtnObj.AddComponent<RectTransform>();
    rectTransform.anchorMin = new Vector2(0, 1);
    rectTransform.anchorMax = new Vector2(0, 1);
    rectTransform.pivot = new Vector2(0, 1);
    rectTransform.anchoredPosition = new Vector2(10, -10);
    rectTransform.sizeDelta = new Vector2(120, 40);

    var image = returnBtnObj.AddComponent<Image>();
    image.color = new Color(0.2f, 0.3f, 0.8f, 0.9f);

    var button = returnBtnObj.AddComponent<Button>();

    // Add text child
    var textObj = new GameObject("Text");
    textObj.transform.SetParent(returnBtnObj.transform, false);

    var textRect = textObj.AddComponent<RectTransform>();
    textRect.anchorMin = Vector2.zero;
    textRect.anchorMax = Vector2.one;
    textRect.offsetMin = Vector2.zero;
    textRect.offsetMax = Vector2.zero;

    var text = textObj.AddComponent<Text>();
    text.text = "返回家园";
    text.font = Resources.GetBuiltinResource<Font>("Arial.ttf");
    text.fontSize = 16;
    text.alignment = TextAnchor.MiddleCenter;
    text.color = Color.white;

    // Add TDReturnButton component
    var returnBtn = returnBtnObj.AddComponent<TowerDefense.Module.TDReturnButton>();

    // Set the button reference via SerializedObject
    var so = new SerializedObject(returnBtn);
    so.FindProperty("_returnButton").objectReferenceValue = button;
    so.FindProperty("_returnButtonObject").objectReferenceValue = returnBtnObj;
    so.ApplyModifiedProperties();

    // Initially hide the return button (will show in module mode)
    returnBtnObj.SetActive(false);

    Debug.Log("ReturnHomeButton added to Canvas");
}

// Save the scene
EditorSceneManager.SaveScene(scene);
Debug.Log("TDGameScene saved");

// Close the scene
EditorSceneManager.CloseScene(scene, false);
Debug.Log("TDGameScene closed");

