var existing = UnityEditor.EditorBuildSettings.scenes;
var list = new System.Collections.Generic.List<UnityEditor.EditorBuildSettingsScene>(existing);

// Add HomeScene at index 0 if not present
string homeScene = "Assets/_Modules/HomeBase/Scenes/HomeScene.scene";
if (!list.Any(s => s.path == homeScene))
{
    list.Insert(0, new UnityEditor.EditorBuildSettingsScene(homeScene, true));
    UnityEditor.EditorBuildSettings.scenes = list.ToArray();
    UnityEngine.Debug.Log("[Build] Added HomeScene to Build Settings at index 0");
}
else
{
    UnityEngine.Debug.Log("[Build] HomeScene already in Build Settings");
}

// Verify
foreach (var s in UnityEditor.EditorBuildSettings.scenes)
{
    UnityEngine.Debug.Log("[Build] " + s.path + " idx=" + System.Array.IndexOf(UnityEditor.EditorBuildSettings.scenes, s) + " enabled=" + s.enabled);
}

